/*
 * Edexcel B (Salters-Nuffield) A-Level Biology — Exam Practice Question Bank
 * 40 written/exam-style questions per topic (S1–S8), 320 questions total.
 * Mix of 1–8 mark questions using Edexcel command words.
 */

const BIOLOGY_EDEXCEL_B_PRACTICE = {

  /* ─────────────────────────────────────────────────────────── S1 */
  'S1': {
    name: 'Lifestyle, Health and Risk',
    questions: [
      { q: 'State the function of the aorta.', marks: 1, markScheme: `• Carries oxygenated blood from the left ventricle to the body / systemic circulation (1)` },
      { q: 'State what is meant by atherosclerosis.', marks: 2, markScheme: `• The build-up of fatty deposits / atheromas in the walls of arteries (1)\n• Leading to narrowing of the lumen / reduced blood flow (1)` },
      { q: 'Describe the structure of an artery.', marks: 3, markScheme: `• Thick muscular wall with elastic tissue (1)\n• Narrow lumen relative to wall thickness (1)\n• No valves (except at the base of the aorta and pulmonary artery) / endothelium lining is smooth (1)` },
      { q: 'Describe the sequence of events in the formation of a blood clot.', marks: 4, markScheme: `• Damage to blood vessel wall exposes collagen (1)\n• Platelets aggregate at the site of damage and release clotting factors (1)\n• A cascade of reactions converts prothrombin to thrombin (1)\n• Thrombin catalyses the conversion of soluble fibrinogen to insoluble fibrin, forming a mesh that traps blood cells (1)` },
      { q: 'Explain why a blockage in a coronary artery can lead to a myocardial infarction.', marks: 3, markScheme: `• Coronary arteries supply the heart muscle with oxygenated blood (1)\n• Blockage reduces / prevents blood flow to an area of heart muscle (1)\n• Cardiac muscle cells are deprived of oxygen for aerobic respiration and die / necrosis (1)` },
      { q: 'Compare the structure of arteries and veins.', marks: 4, markScheme: `• Arteries have thicker muscular/elastic walls than veins (1)\n• Arteries have a narrower lumen relative to their diameter than veins (1)\n• Veins have valves to prevent backflow; arteries generally do not (1)\n• Both have an endothelial lining but arteries need to withstand higher pressure (1)` },
      { q: 'Describe how the structure of a capillary is related to its function.', marks: 3, markScheme: `• Wall is one cell thick / single layer of endothelium, allowing short diffusion distance for rapid exchange (1)\n• Very narrow lumen forces red blood cells to pass through in single file, increasing surface area for gas exchange (1)\n• Permeable walls / small gaps between cells allow exchange of substances with surrounding tissues (1)` },
      { q: 'Explain the difference between correlation and causation, using an example related to cardiovascular disease.', marks: 3, markScheme: `• Correlation means two variables change together / there is a statistical relationship (1)\n• Causation means one variable directly causes a change in the other (1)\n• Example: high saturated fat intake correlates with increased CVD risk, but other confounding factors (exercise, genetics) mean the relationship may not be directly causal without controlled experiments (1)` },
      { q: 'Describe how water molecules form hydrogen bonds.', marks: 2, markScheme: `• Water is a polar molecule with a slightly positive hydrogen end and slightly negative oxygen end (1)\n• Hydrogen bonds form between the slightly positive H of one molecule and the slightly negative O of another (1)` },
      { q: 'Explain how the properties of water make it important as a transport medium in blood.', marks: 4, markScheme: `• Water is a good solvent for polar/ionic substances such as glucose, amino acids and mineral ions (1)\n• High specific heat capacity means blood temperature remains relatively stable (1)\n• Cohesion between water molecules helps maintain blood flow / blood pressure (1)\n• Water is liquid at body temperature, allowing it to flow through vessels easily (1)` },
      { q: 'State what is meant by the term risk factor in relation to disease.', marks: 1, markScheme: `• A factor / variable that increases the probability / likelihood of developing a disease (1)` },
      { q: 'Explain why smoking increases the risk of cardiovascular disease.', marks: 4, markScheme: `• Carbon monoxide in smoke binds to haemoglobin, reducing oxygen-carrying capacity (1)\n• Nicotine increases heart rate and blood pressure, increasing strain on the heart (1)\n• Chemicals in smoke damage the endothelium of artery walls, triggering atherosclerosis (1)\n• Smoking increases platelet stickiness, making blood clots more likely (1)` },
      { q: 'Describe the role of HDLs and LDLs in relation to cholesterol and cardiovascular disease.', marks: 4, markScheme: `• LDLs transport cholesterol from the liver to the tissues / cells (1)\n• Excess LDLs deposit cholesterol in artery walls, contributing to atheroma formation (1)\n• HDLs transport cholesterol from the tissues back to the liver for breakdown / excretion (1)\n• High HDL:LDL ratio is associated with reduced risk of CVD (1)` },
      { q: 'Evaluate the evidence linking diet to cardiovascular disease.', marks: 6, markScheme: `• Saturated fat intake raises blood LDL cholesterol levels which promotes atherosclerosis (1)\n• High salt intake increases blood pressure / hypertension which damages artery walls (1)\n• Epidemiological studies show strong correlations between diet and CVD incidence (1)\n• However, confounding variables (exercise, smoking, genetics, stress) make it difficult to establish direct causation (1)\n• Intervention studies (e.g. changing diet) support a causal link in some cases (1)\n• Evaluation: evidence is strong overall but individual risk depends on multiple interacting factors, not diet alone (1)` },
      { q: 'Calculate the cardiac output if heart rate is 72 beats per minute and stroke volume is 70 cm\u00b3.', marks: 2, markScheme: `• Cardiac output = heart rate \u00d7 stroke volume (1)\n• = 72 \u00d7 70 = 5040 cm\u00b3/min (1)` },
      { q: 'Describe the events of the cardiac cycle during ventricular systole.', marks: 3, markScheme: `• Ventricles contract, increasing pressure inside the ventricles (1)\n• Atrioventricular valves close (producing the first heart sound) preventing backflow to the atria (1)\n• Semilunar valves open as ventricular pressure exceeds pressure in the aorta/pulmonary artery, and blood is forced out (1)` },
      { q: 'Explain the role of the sinoatrial node (SAN) in controlling heart rate.', marks: 3, markScheme: `• The SAN is the pacemaker located in the wall of the right atrium (1)\n• It generates electrical impulses that spread across the atria causing atrial contraction / atrial systole (1)\n• Impulses are then passed to the atrioventricular node (AVN) and then along the bundle of His / Purkinje fibres to cause ventricular contraction (1)` },
      { q: 'Suggest why the left ventricle has a thicker wall than the right ventricle.', marks: 2, markScheme: `• The left ventricle pumps blood to the whole body / systemic circulation, which is at a greater distance (1)\n• A thicker muscular wall generates higher pressure to push blood through the systemic circuit (1)` },
      { q: 'State what is meant by the term thrombosis.', marks: 1, markScheme: `• The formation of a blood clot (thrombus) within a blood vessel, obstructing blood flow (1)` },
      { q: 'Explain how high blood pressure increases the risk of cardiovascular disease.', marks: 3, markScheme: `• High blood pressure damages the endothelial lining of arteries (1)\n• Damage triggers an inflammatory response and deposition of cholesterol / atheroma formation (1)\n• This narrows arteries and can lead to thrombus formation / increased risk of heart attack or stroke (1)` },
      { q: 'Describe the role of platelets in the blood clotting process.', marks: 3, markScheme: `• Platelets are cell fragments that circulate in the blood (1)\n• When a vessel is damaged, platelets adhere to exposed collagen and aggregate to form a platelet plug (1)\n• Platelets release clotting factors that initiate the clotting cascade / conversion of fibrinogen to fibrin (1)` },
      { q: 'Explain why water has a high specific heat capacity and the biological significance of this.', marks: 3, markScheme: `• Many hydrogen bonds must be broken to raise water temperature (1)\n• This means water resists rapid temperature changes (1)\n• Biological significance: provides a stable environment for metabolic reactions / maintains relatively constant body/blood temperature (1)` },
      { q: 'Outline how a cohort study can be used to investigate risk factors for cardiovascular disease.', marks: 3, markScheme: `• A large group of people is followed over a long period of time (1)\n• Data is collected on lifestyle factors (diet, smoking, exercise) and health outcomes (CVD incidence) (1)\n• Statistical analysis is used to identify associations between risk factors and disease (1)` },
      { q: 'Describe the structure of the heart, including the names of the four chambers and associated blood vessels.', marks: 4, diagram: true, markScheme: `• Right atrium receives deoxygenated blood from the vena cava; right ventricle pumps it to the lungs via the pulmonary artery (1)\n• Left atrium receives oxygenated blood from the pulmonary veins; left ventricle pumps it to the body via the aorta (1)\n• Atrioventricular valves (tricuspid on right, bicuspid/mitral on left) separate atria and ventricles (1)\n• Septum separates the left and right sides of the heart, preventing mixing of oxygenated and deoxygenated blood (1)` },
      { q: 'Draw and label a diagram of a cross-section through an artery, showing the key tissue layers.', marks: 3, diagram: true, markScheme: `• Inner endothelium / tunica intima drawn and labelled (1)\n• Thick middle layer of smooth muscle and elastic fibres / tunica media drawn and labelled (1)\n• Outer layer of connective tissue / tunica adventitia drawn and labelled, with small lumen relative to wall thickness (1)` },
      { q: 'Explain the importance of the double circulatory system in mammals.', marks: 3, markScheme: `• Blood passes through the heart twice in one complete circuit (pulmonary and systemic) (1)\n• This maintains high pressure in the systemic circulation for efficient delivery of oxygen/nutrients to tissues (1)\n• Pressure is lower in the pulmonary circuit, preventing damage to the delicate gas exchange surfaces in the lungs (1)` },
      { q: 'Explain why doctors measure both systolic and diastolic blood pressure.', marks: 2, markScheme: `• Systolic pressure measures the pressure during ventricular contraction, indicating the force of heart output (1)\n• Diastolic pressure measures the pressure during relaxation, indicating the resistance of blood vessels / baseline arterial pressure; both are needed for a full picture of cardiovascular health (1)` },
      { q: 'Suggest why the incidence of CVD varies between different countries.', marks: 3, markScheme: `• Differences in diet — e.g. Mediterranean diets are associated with lower CVD rates (1)\n• Differences in prevalence of risk factors such as smoking, obesity, and physical inactivity (1)\n• Genetic differences between populations / differences in healthcare access and screening programmes (1)` },
      { q: 'Describe how to investigate the effect of different concentrations of salt solution on the mass of potato tissue.', marks: 4, markScheme: `• Cut potato cylinders of equal size/mass and blot dry, then weigh (1)\n• Place cylinders in different concentrations of salt/sucrose solution for a fixed time (1)\n• Remove, blot dry and reweigh (1)\n• Calculate percentage change in mass and plot against concentration to determine the water potential of potato cells (1)` },
      { q: 'Explain the difference between an embolism and a thrombus.', marks: 2, markScheme: `• A thrombus is a blood clot that forms at a specific site within a blood vessel (1)\n• An embolism occurs when part of a thrombus breaks away and travels through the bloodstream to block a vessel elsewhere (1)` },
      { q: 'Evaluate the use of statins in reducing the risk of cardiovascular disease.', marks: 5, markScheme: `• Statins reduce blood cholesterol by inhibiting the enzyme involved in cholesterol synthesis in the liver (1)\n• Clinical trials show statins significantly reduce the risk of heart attack and stroke (1)\n• They are widely prescribed and relatively inexpensive (1)\n• However, they can have side effects including muscle pain, liver damage, and digestive problems (1)\n• Evaluation: benefits generally outweigh risks for high-risk individuals, but lifestyle changes should also be encouraged alongside medication (1)` },
      { q: 'State two properties of water that result from hydrogen bonding.', marks: 2, markScheme: `• High specific heat capacity (1)\n• High latent heat of vaporisation / cohesion / surface tension / good solvent properties (any one) (1)` },
      { q: 'Describe how pressure changes in the heart during one cardiac cycle.', marks: 4, diagram: true, markScheme: `• During atrial systole, atrial pressure rises above ventricular pressure, forcing blood through AV valves (1)\n• During ventricular systole, ventricular pressure rises rapidly above atrial pressure, closing AV valves, and exceeds arterial pressure, opening semilunar valves (1)\n• During diastole, ventricular pressure falls below arterial pressure, closing semilunar valves (1)\n• Ventricular pressure falls below atrial pressure, AV valves open and passive filling occurs (1)` },
      { q: 'Calculate BMI for a person who is 1.75 m tall and weighs 82 kg. State whether this is classified as overweight.', marks: 2, markScheme: `• BMI = 82 / (1.75)\u00b2 = 82 / 3.0625 = 26.8 (1)\n• This is classified as overweight (BMI 25\u201329.9) (1)` },
      { q: 'Explain why unsaturated fats are generally considered healthier than saturated fats.', marks: 3, markScheme: `• Unsaturated fats contain one or more C=C double bonds, giving them kinks that prevent close packing / they are liquid at room temperature (1)\n• Saturated fats increase blood LDL cholesterol levels, promoting atherosclerosis (1)\n• Unsaturated fats can increase HDL cholesterol / do not raise LDL levels, reducing CVD risk (1)` },
      { q: 'Outline the role of the autonomic nervous system in controlling heart rate.', marks: 3, markScheme: `• The sympathetic nervous system increases heart rate by releasing noradrenaline at the SAN (1)\n• The parasympathetic nervous system (vagus nerve) decreases heart rate by releasing acetylcholine at the SAN (1)\n• The cardiovascular centre in the medulla oblongata coordinates these signals in response to blood pressure and blood CO\u2082 levels (1)` },
      { q: 'Suggest why epidemiological studies on diet and CVD often produce conflicting results.', marks: 3, markScheme: `• Different study designs and sample sizes may produce different levels of statistical significance (1)\n• Self-reported dietary data is unreliable / recall bias (1)\n• Confounding variables (genetics, lifestyle, socioeconomic status) are difficult to control between studies (1)` },
      { q: 'Explain how an ECG trace can be used to detect abnormalities in heart function.', marks: 3, diagram: true, markScheme: `• The P wave represents atrial contraction; abnormal P waves may indicate atrial problems (1)\n• The QRS complex represents ventricular contraction; widened QRS may indicate bundle branch block (1)\n• The T wave represents ventricular repolarisation; changes in timing or shape of any wave can indicate arrhythmias, ischaemia or other cardiac conditions (1)` },
      { q: 'State the difference between a pulmonary embolism and a deep vein thrombosis.', marks: 2, markScheme: `• A deep vein thrombosis (DVT) is a blood clot that forms in a deep vein, usually in the leg (1)\n• A pulmonary embolism occurs when a clot (often from a DVT) travels to and blocks an artery in the lungs (1)` },
      { q: 'Explain why someone with a family history of CVD may be advised to have regular health checks even if they have a healthy lifestyle.', marks: 2, markScheme: `• Genetic factors can predispose individuals to high blood cholesterol, high blood pressure, or atherosclerosis regardless of lifestyle (1)\n• Regular monitoring allows early detection and treatment (e.g. statins, blood pressure medication) to reduce risk (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S2 */
  'S2': {
    name: 'Genes and Health',
    questions: [
      { q: 'State the components of a nucleotide.', marks: 2, markScheme: `• A pentose sugar (deoxyribose in DNA / ribose in RNA) (1)\n• A phosphate group and a nitrogenous base (A, T, C, G in DNA; A, U, C, G in RNA) (1)` },
      { q: 'Describe the structure of DNA.', marks: 4, markScheme: `• Two polynucleotide strands wound into a double helix (1)\n• Strands are antiparallel (run in opposite directions, 5\u2032 to 3\u2032 and 3\u2032 to 5\u2032) (1)\n• Complementary base pairing: adenine pairs with thymine (two hydrogen bonds), cytosine pairs with guanine (three hydrogen bonds) (1)\n• Sugar-phosphate backbone on the outside with bases on the inside (1)` },
      { q: 'Describe the fluid mosaic model of cell membrane structure.', marks: 4, markScheme: `• Phospholipid bilayer forms the basic structure with hydrophilic heads facing outward and hydrophobic tails facing inward (1)\n• Integral/transmembrane proteins span the bilayer; peripheral proteins are on the surface (1)\n• Glycoproteins and glycolipids are present on the outer surface for cell signalling / recognition (1)\n• The membrane is described as fluid because phospholipids and proteins can move laterally (1)` },
      { q: 'Explain how the structure of the gas exchange system is adapted for efficient gas exchange.', marks: 4, markScheme: `• Large surface area provided by millions of alveoli (1)\n• Thin walls (one cell thick) of alveoli and capillaries provide a short diffusion distance (1)\n• Rich blood supply maintains a steep concentration gradient for O\u2082 and CO\u2082 (1)\n• Ventilation maintains the concentration gradient by bringing in fresh air and removing stale air (1)` },
      { q: 'Describe the process of transcription.', marks: 4, markScheme: `• RNA polymerase binds to the promoter region on the template/antisense strand of DNA (1)\n• The DNA double helix unwinds and hydrogen bonds between bases break (1)\n• Free RNA nucleotides align with complementary bases on the template strand (A with U, T with A, C with G, G with C) (1)\n• RNA polymerase joins the nucleotides together to form a pre-mRNA strand, which is then processed into mature mRNA (1)` },
      { q: 'Describe the process of translation.', marks: 5, markScheme: `• mRNA binds to a ribosome at the start codon (AUG) (1)\n• tRNA molecules with complementary anticodons bring specific amino acids to the ribosome (1)\n• The ribosome moves along the mRNA, reading codons in sequence (1)\n• Peptide bonds form between adjacent amino acids, building a polypeptide chain (1)\n• Translation continues until a stop codon is reached and the polypeptide is released (1)` },
      { q: 'Explain the role of the CFTR protein in healthy individuals.', marks: 3, markScheme: `• CFTR is a chloride ion channel protein located in epithelial cell membranes (1)\n• It allows chloride ions to move out of cells into the mucus / lumen (1)\n• Water follows by osmosis, keeping the mucus thin and fluid (1)` },
      { q: 'Explain how a mutation in the CFTR gene causes the symptoms of cystic fibrosis.', marks: 4, markScheme: `• A deletion of three bases (most commonly \u0394F508) results in a misfolded CFTR protein that is not inserted into the cell membrane (1)\n• Chloride ions cannot be transported out of epithelial cells (1)\n• Water is not drawn out by osmosis, resulting in thick, sticky mucus (1)\n• This mucus blocks airways, pancreatic ducts, and reproductive tracts, causing breathing difficulties, digestive problems, and infertility (1)` },
      { q: 'State the meaning of the term genotype.', marks: 1, markScheme: `• The genetic makeup / combination of alleles an organism has for a particular gene (1)` },
      { q: 'State the meaning of the term phenotype.', marks: 1, markScheme: `• The observable characteristics of an organism, resulting from the interaction of genotype and environment (1)` },
      { q: 'A cross is carried out between two parents who are both carriers of cystic fibrosis (Cc \u00d7 Cc). Draw a genetic diagram and state the probability of a child having cystic fibrosis.', marks: 4, diagram: true, markScheme: `• Correct parental genotypes identified: Cc \u00d7 Cc (1)\n• Correct gametes shown: C and c from each parent (1)\n• Correct Punnett square: CC, Cc, Cc, cc (1)\n• Probability of affected child (cc) = 1 in 4 / 25% (1)` },
      { q: 'Explain the difference between a gene mutation and a chromosomal mutation.', marks: 2, markScheme: `• A gene mutation is a change in the nucleotide/base sequence of a single gene (e.g. substitution, deletion, insertion) (1)\n• A chromosomal mutation involves changes to the structure or number of whole chromosomes (e.g. translocation, non-disjunction) (1)` },
      { q: 'Explain why a substitution mutation may not always change the amino acid sequence of a protein.', marks: 2, markScheme: `• The genetic code is degenerate / redundant, meaning multiple codons can code for the same amino acid (1)\n• A substitution in the third base of a codon (wobble position) may still code for the same amino acid / silent mutation (1)` },
      { q: 'Explain why a deletion mutation is usually more harmful than a substitution mutation.', marks: 3, markScheme: `• A deletion causes a frameshift, changing every codon downstream of the mutation (1)\n• This alters all subsequent amino acids in the polypeptide (1)\n• A substitution only affects one codon / one amino acid (unless it creates a stop codon), so the rest of the protein is unchanged (1)` },
      { q: 'Describe the role of carrier proteins in facilitated diffusion.', marks: 3, markScheme: `• Carrier proteins are specific to particular molecules (1)\n• The molecule binds to the carrier protein, causing it to change shape (1)\n• The molecule is released on the other side of the membrane, moving down its concentration gradient without energy input (1)` },
      { q: 'Describe the structure and function of channel proteins in cell membranes.', marks: 2, markScheme: `• Channel proteins form water-filled pores through the membrane (1)\n• They allow specific polar molecules or ions to pass through by facilitated diffusion down their concentration gradient (1)` },
      { q: 'Explain how the structure of a tRNA molecule is related to its function in translation.', marks: 3, markScheme: `• Cloverleaf shape with an anticodon loop that is complementary to a specific mRNA codon (1)\n• An amino acid attachment site (3\u2032 end / CCA sequence) carries the specific amino acid (1)\n• The specific shape ensures the correct amino acid is brought to the ribosome for each codon / specificity of the genetic code (1)` },
      { q: 'Evaluate the arguments for and against genetic screening for cystic fibrosis.', marks: 6, markScheme: `• For: allows carriers to make informed decisions about having children (1)\n• For: early diagnosis enables early treatment, improving quality of life (1)\n• For: can reduce incidence of the condition in the population over time (1)\n• Against: may cause anxiety or psychological stress for individuals found to be carriers (1)\n• Against: raises ethical concerns about potential discrimination (insurance, employment) (1)\n• Against: risk of false positives/negatives; testing may lead to difficult decisions about pregnancy termination (1)` },
      { q: 'Describe the differences between DNA and RNA.', marks: 3, markScheme: `• DNA contains deoxyribose sugar; RNA contains ribose sugar (1)\n• DNA is double-stranded; RNA is single-stranded (1)\n• DNA contains thymine; RNA contains uracil instead (1)` },
      { q: 'Explain how gene therapy could potentially treat cystic fibrosis.', marks: 4, markScheme: `• A normal/functional copy of the CFTR gene is isolated and inserted into a vector (e.g. liposome or adenovirus) (1)\n• The vector delivers the gene to the epithelial cells of the lungs (e.g. via aerosol inhaler) (1)\n• The functional gene is expressed, producing normal CFTR protein that allows chloride ion transport (1)\n• Limitations: effects are temporary as epithelial cells are replaced; gene may not integrate into the genome permanently; immune response to viral vectors (1)` },
      { q: 'State what is meant by the term codon.', marks: 1, markScheme: `• A sequence of three bases / triplet on mRNA that codes for a specific amino acid (or stop signal) (1)` },
      { q: 'Explain why the genetic code is described as universal and non-overlapping.', marks: 2, markScheme: `• Universal means the same codons code for the same amino acids in almost all organisms (1)\n• Non-overlapping means each base in the sequence is part of only one codon / codons are read sequentially without sharing bases (1)` },
      { q: 'Describe how Fick\u2019s law applies to gas exchange in the lungs.', marks: 3, markScheme: `• Rate of diffusion is proportional to surface area \u00d7 concentration difference / thickness of membrane (1)\n• The alveoli provide a large surface area and thin walls to maximise the rate (1)\n• Ventilation and blood flow maintain a steep concentration gradient for O\u2082 and CO\u2082 (1)` },
      { q: 'Describe the role of the diaphragm and intercostal muscles in ventilation.', marks: 4, markScheme: `• During inspiration: external intercostal muscles contract, raising the rib cage up and out (1)\n• The diaphragm contracts and flattens (1)\n• This increases thoracic volume, decreasing pressure below atmospheric, so air is drawn in (1)\n• During expiration (at rest): these muscles relax, elastic recoil of lungs decreases thoracic volume, increasing pressure, pushing air out (1)` },
      { q: 'Explain the effect of temperature on membrane permeability.', marks: 4, markScheme: `• At low temperatures, phospholipids are closely packed and membrane is less fluid / less permeable (1)\n• As temperature increases, kinetic energy increases, phospholipids move more, membrane becomes more fluid and permeable (1)\n• Above approximately 40\u00b0C, proteins begin to denature, disrupting channel and carrier protein function (1)\n• The phospholipid bilayer becomes very permeable / loses its integrity, and cell contents leak out (1)` },
      { q: 'Draw a labelled diagram of the basic structure of an amino acid.', marks: 2, diagram: true, markScheme: `• Central carbon atom with an amino group (\u2013NH\u2082) and a carboxyl group (\u2013COOH) correctly drawn (1)\n• R group / variable side chain and hydrogen atom attached to the central carbon shown (1)` },
      { q: 'Explain how a polypeptide chain folds to form a functional protein.', marks: 4, markScheme: `• Primary structure: the specific sequence of amino acids in the polypeptide chain (1)\n• Secondary structure: the chain folds into alpha-helices and beta-pleated sheets held by hydrogen bonds (1)\n• Tertiary structure: further folding into a 3D shape held by hydrogen bonds, ionic bonds, disulfide bridges, and hydrophobic interactions (1)\n• Quaternary structure (if applicable): two or more polypeptide chains associate to form the functional protein (1)` },
      { q: 'Explain the role of enzymes in digestion of food in the small intestine.', marks: 3, markScheme: `• Enzymes are biological catalysts that lower the activation energy of reactions (1)\n• Specific enzymes (e.g. lipase, protease, amylase) hydrolyse large insoluble food molecules into smaller soluble molecules (1)\n• These smaller molecules (e.g. amino acids, fatty acids, glucose) can be absorbed across the intestinal wall into the blood (1)` },
      { q: 'A couple are both carriers for cystic fibrosis. They already have one unaffected child. Calculate the probability that their next child will have cystic fibrosis.', marks: 2, markScheme: `• Each pregnancy is an independent event (1)\n• Probability = 1/4 / 25% (the previous child does not affect the probability for the next) (1)` },
      { q: 'Describe how gel electrophoresis separates DNA fragments.', marks: 4, markScheme: `• DNA fragments are loaded into wells in an agarose gel (1)\n• An electric current is applied; DNA is negatively charged so moves toward the positive electrode (1)\n• Smaller fragments move faster / further through the gel (1)\n• Fragments separate by size, forming a pattern of bands that can be visualised with a stain or UV light (1)` },
      { q: 'Suggest why gene therapy for cystic fibrosis has had limited success so far.', marks: 3, markScheme: `• The immune system may attack the viral vector, reducing efficiency (1)\n• Lung epithelial cells are continually replaced, so treatment needs repeating (1)\n• Difficulty getting the gene into enough cells to produce sufficient functional CFTR protein (1)` },
      { q: 'Draw and label a diagram showing the structure of a section of DNA, including at least two nucleotides on each strand.', marks: 4, diagram: true, markScheme: `• Two antiparallel strands shown with sugar-phosphate backbone on outside (1)\n• Correct complementary base pairs (A\u2013T and C\u2013G) shown between the strands (1)\n• Hydrogen bonds between bases indicated (two between A\u2013T, three between C\u2013G) (1)\n• Deoxyribose sugar, phosphate group, and bases correctly labelled on at least one nucleotide (1)` },
      { q: 'Explain why membrane-bound receptors are important for cell signalling.', marks: 3, markScheme: `• Receptor proteins on the cell surface have a specific complementary shape to signalling molecules / ligands (1)\n• When a signalling molecule binds, it causes a conformational change in the receptor (1)\n• This triggers a response inside the cell (e.g. opening of ion channels, activation of enzymes, gene expression changes) (1)` },
      { q: 'State the difference between exons and introns.', marks: 2, markScheme: `• Exons are coding sequences that are expressed / translated into protein (1)\n• Introns are non-coding sequences that are removed during mRNA processing / splicing (1)` },
      { q: 'Describe the process of mRNA splicing.', marks: 3, markScheme: `• After transcription, the pre-mRNA contains both introns and exons (1)\n• Introns are cut out / removed by spliceosomes (1)\n• Exons are joined together to form mature mRNA, which leaves the nucleus through nuclear pores (1)` },
      { q: 'Explain the ethical issues surrounding preimplantation genetic diagnosis (PGD).', marks: 4, markScheme: `• PGD involves testing embryos created by IVF for genetic conditions before implantation (1)\n• Allows selection of unaffected embryos, reducing the chance of a child inheriting a genetic condition (1)\n• Ethical concerns: destruction of embryos carrying the condition raises questions about the moral status of embryos (1)\n• Could lead to "designer babies" / selection for non-medical traits; raises issues of equality and access (1)` },
      { q: 'Explain how antibiotics work and why they are not effective against viruses.', marks: 3, markScheme: `• Antibiotics target bacterial cell structures or processes (e.g. cell wall synthesis, protein synthesis, DNA replication) (1)\n• Viruses do not have their own cellular structures / metabolism; they replicate inside host cells using host machinery (1)\n• Therefore antibiotics have no target to act upon in viruses (1)` },
      { q: 'Outline the role of mRNA, tRNA and ribosomes in protein synthesis.', marks: 3, markScheme: `• mRNA carries the genetic code from the DNA in the nucleus to the ribosome in the cytoplasm (1)\n• Ribosomes read the mRNA codons and provide the site where amino acids are assembled into polypeptides (1)\n• tRNA molecules carry specific amino acids to the ribosome, matching their anticodon to the mRNA codon (1)` },
      { q: 'Describe how to investigate the effect of substrate concentration on enzyme activity using catalase and hydrogen peroxide.', marks: 4, markScheme: `• Prepare a range of hydrogen peroxide concentrations (e.g. using serial dilution) (1)\n• Add a fixed amount of catalase (e.g. potato extract) to each concentration and collect the oxygen gas produced using a gas syringe or inverted measuring cylinder (1)\n• Measure the volume of gas produced at fixed time intervals (1)\n• Control variables: temperature, pH, volume of enzyme, and total volume of reaction mixture (1)` },
      { q: 'Explain how the structure of the phospholipid bilayer acts as a barrier to most water-soluble substances.', marks: 2, markScheme: `• The hydrophobic fatty acid tails of the phospholipids form the interior of the bilayer (1)\n• Polar / charged / water-soluble molecules cannot pass through the hydrophobic core, so require transport proteins (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S3 */
  'S3': {
    name: 'Voice of the Genome',
    questions: [
      { q: 'State what is meant by the cell cycle.', marks: 1, markScheme: `• The sequence of events that takes place in a cell, resulting in cell division and the production of two daughter cells (1)` },
      { q: 'Describe the stages of the cell cycle.', marks: 3, markScheme: `• Interphase: the cell grows, replicates its DNA, and prepares for division (G1, S, G2 phases) (1)\n• Mitosis: the nucleus divides into two genetically identical nuclei (prophase, metaphase, anaphase, telophase) (1)\n• Cytokinesis: the cytoplasm divides, producing two separate daughter cells (1)` },
      { q: 'Describe the events that occur during the S phase of interphase.', marks: 2, markScheme: `• DNA replication occurs / each chromosome is copied to form two identical sister chromatids (1)\n• Sister chromatids are joined at the centromere (1)` },
      { q: 'Describe the events of mitosis in the correct order.', marks: 4, markScheme: `• Prophase: chromosomes condense and become visible, nuclear envelope breaks down, spindle fibres form from centrioles (1)\n• Metaphase: chromosomes line up at the cell equator / metaphase plate, attached to spindle fibres at their centromeres (1)\n• Anaphase: centromeres divide and sister chromatids are pulled to opposite poles by shortening spindle fibres (1)\n• Telophase: chromatids reach the poles, nuclear envelopes reform around each set, chromosomes decondense (1)` },
      { q: 'Explain the importance of mitosis.', marks: 3, markScheme: `• Produces two genetically identical daughter cells for growth and repair of tissues (1)\n• Maintains the diploid chromosome number (1)\n• Ensures genetic consistency / all body cells have the same genome (1)` },
      { q: 'Compare mitosis and meiosis.', marks: 6, markScheme: `• Mitosis produces 2 daughter cells; meiosis produces 4 (1)\n• Mitosis produces diploid cells; meiosis produces haploid cells (1)\n• Mitosis produces genetically identical cells; meiosis produces genetically different cells (1)\n• Mitosis involves one division; meiosis involves two divisions (meiosis I and II) (1)\n• Crossing over occurs in meiosis (prophase I) but not in mitosis (1)\n• Independent assortment of homologous pairs occurs in meiosis I but not in mitosis (1)` },
      { q: 'Explain how meiosis produces genetic variation.', marks: 4, markScheme: `• Crossing over in prophase I: homologous chromosomes exchange genetic material at chiasmata, producing recombinant chromatids (1)\n• Independent assortment in metaphase I: homologous pairs line up randomly at the equator, so different combinations of maternal and paternal chromosomes are distributed to daughter cells (1)\n• Random fertilisation: any sperm can fuse with any egg, combining two unique sets of chromosomes (1)\n• These processes together produce offspring with unique combinations of alleles (1)` },
      { q: 'State what is meant by the term stem cell.', marks: 2, markScheme: `• An undifferentiated cell (1)\n• That can divide to produce more stem cells (self-renew) and differentiate into specialised cell types (1)` },
      { q: 'Explain the difference between totipotent, pluripotent and multipotent stem cells.', marks: 3, markScheme: `• Totipotent cells can differentiate into any cell type, including extra-embryonic tissues (e.g. placenta); found in early embryo up to 8-cell stage (1)\n• Pluripotent cells can differentiate into any cell type of the body but not extra-embryonic tissues; found in the inner cell mass of the blastocyst (1)\n• Multipotent cells can only differentiate into a limited range of cell types within a particular tissue; found in adults, e.g. haematopoietic stem cells (1)` },
      { q: 'Explain how cells become specialised through differentiation.', marks: 3, markScheme: `• All body cells contain the same genome / same DNA (1)\n• During differentiation, specific genes are switched on / expressed while others are switched off (1)\n• This produces specific proteins that give the cell its specialised structure and function (1)` },
      { q: 'Describe the role of transcription factors in gene expression.', marks: 3, markScheme: `• Transcription factors are proteins that bind to specific DNA sequences near the promoter region of a gene (1)\n• They can activate transcription by helping RNA polymerase bind to the promoter (activators) (1)\n• Or they can repress transcription by blocking RNA polymerase binding (repressors) (1)` },
      { q: 'Explain what is meant by epigenetics.', marks: 3, markScheme: `• Epigenetics refers to heritable changes in gene expression that do not involve changes to the DNA base sequence (1)\n• These changes are caused by modifications such as DNA methylation (adding methyl groups to DNA) or histone modification (1)\n• These modifications can switch genes on or off and can be influenced by environmental factors (1)` },
      { q: 'Explain how DNA methylation can silence a gene.', marks: 3, markScheme: `• Methyl groups are added to cytosine bases in the DNA, often at CpG islands near promoter regions (1)\n• Methylation prevents transcription factors / RNA polymerase from binding to the promoter (1)\n• The gene is not transcribed and the protein it codes for is not produced (1)` },
      { q: 'Explain how histone modification affects gene expression.', marks: 3, markScheme: `• DNA is wrapped around histone proteins to form chromatin (1)\n• Acetylation of histones loosens the DNA-histone association, making DNA more accessible to transcription factors / increasing transcription (1)\n• Deacetylation / methylation of histones tightens the DNA-histone association, making DNA less accessible / decreasing transcription (1)` },
      { q: 'Describe the stages of early embryo development from fertilisation to implantation.', marks: 4, markScheme: `• Fertilisation: sperm and egg nuclei fuse to form a diploid zygote (1)\n• The zygote undergoes mitotic cell divisions (cleavage) to form a ball of cells / morula (1)\n• Continued division forms a blastocyst with an inner cell mass (which becomes the embryo) and an outer layer (trophoblast, which becomes the placenta) (1)\n• The blastocyst implants into the endometrium / uterus lining approximately 6\u20137 days after fertilisation (1)` },
      { q: 'Explain the role of the homeobox genes (Hox genes) in development.', marks: 3, markScheme: `• Homeobox genes code for transcription factors that regulate the expression of other genes (1)\n• They control the body plan / determine the identity of body segments during embryonic development (1)\n• Mutations in homeobox genes can cause major developmental abnormalities, e.g. structures developing in the wrong body region (1)` },
      { q: 'Draw and label a diagram showing the stages of mitosis in an animal cell.', marks: 4, diagram: true, markScheme: `• Prophase: condensed chromosomes visible, spindle forming, no nuclear envelope (1)\n• Metaphase: chromosomes aligned at the equator, attached to spindle fibres at centromeres (1)\n• Anaphase: sister chromatids separating and moving to opposite poles (1)\n• Telophase: two groups of chromosomes at poles, nuclear envelopes reforming, cell beginning to divide (1)` },
      { q: 'Suggest how environmental factors can influence phenotype through epigenetic mechanisms.', marks: 3, markScheme: `• Diet, stress, toxins, or temperature can cause epigenetic changes such as DNA methylation or histone modification (1)\n• These changes alter gene expression without changing the DNA sequence (1)\n• Example: identical twins may develop different phenotypes due to different environmental exposures causing different epigenetic patterns (1)` },
      { q: 'Evaluate the use of embryonic stem cells in medical research and treatment.', marks: 6, markScheme: `• Advantage: pluripotent, so can differentiate into almost any cell type for treating diseases such as Parkinson\u2019s, diabetes, spinal cord injuries (1)\n• Advantage: could provide a source of replacement cells/tissues, reducing the need for organ transplants (1)\n• Advantage: can be used to study developmental biology and test drug efficacy (1)\n• Disadvantage: destruction of embryos raises ethical concerns about the moral status of the embryo (1)\n• Disadvantage: risk of immune rejection if donor cells are not matched to the patient (1)\n• Disadvantage: risk of uncontrolled cell division / tumour formation if differentiation is not properly controlled (1)` },
      { q: 'Explain the debate surrounding nature vs nurture in determining phenotype.', marks: 4, markScheme: `• Nature: genes inherited from parents determine many characteristics (e.g. eye colour, blood group) (1)\n• Nurture: environmental factors (diet, lifestyle, experience) also influence phenotype (1)\n• Many characteristics are influenced by both (e.g. height has a genetic component but is also affected by nutrition) (1)\n• Epigenetic mechanisms provide a link between nature and nurture, showing how environment can alter gene expression without changing DNA (1)` },
      { q: 'Explain why cells in G0 phase do not divide.', marks: 2, markScheme: `• G0 is a quiescent / resting phase where the cell has exited the cell cycle (1)\n• The cell carries out its normal functions but does not replicate its DNA or prepare for division; some cells (e.g. neurones) remain in G0 permanently (1)` },
      { q: 'Describe how uncontrolled cell division can lead to tumour formation.', marks: 3, markScheme: `• Mutations in genes that regulate the cell cycle (proto-oncogenes and tumour suppressor genes) can lead to uncontrolled mitosis (1)\n• Cells divide rapidly without normal checkpoints, forming a mass of abnormal cells / tumour (1)\n• Benign tumours are contained; malignant tumours can invade surrounding tissues and metastasise to other parts of the body (1)` },
      { q: 'State the role of tumour suppressor genes.', marks: 2, markScheme: `• Tumour suppressor genes code for proteins that inhibit / slow down cell division or promote apoptosis (1)\n• Mutations that inactivate tumour suppressor genes can lead to uncontrolled cell division / cancer (1)` },
      { q: 'Explain what is meant by apoptosis and why it is important.', marks: 3, markScheme: `• Apoptosis is programmed cell death, a controlled process where cells self-destruct (1)\n• It involves cell shrinkage, chromatin condensation, DNA fragmentation, and formation of apoptotic bodies that are phagocytosed (1)\n• Important for removing damaged, infected, or unnecessary cells during development and tissue maintenance (1)` },
      { q: 'Describe how to use a light microscope to observe the stages of mitosis in a root tip squash.', marks: 4, markScheme: `• Cut 1\u20132 cm of root tip and place in warm hydrochloric acid to separate cells / break down middle lamellae (1)\n• Place on a microscope slide, add a stain (e.g. acetic orcein / toluidine blue) to make chromosomes visible (1)\n• Squash the root tip gently with a coverslip to spread cells into a single layer (1)\n• Observe under the microscope and identify cells at different stages of mitosis (1)` },
      { q: 'Calculate the mitotic index if 24 out of 120 cells observed are undergoing mitosis.', marks: 2, markScheme: `• Mitotic index = number of cells in mitosis / total number of cells (1)\n• = 24 / 120 = 0.20 / 20% (1)` },
      { q: 'Explain why meiosis is necessary for sexual reproduction.', marks: 3, markScheme: `• Meiosis produces haploid gametes (n) from diploid cells (2n) (1)\n• When two haploid gametes fuse at fertilisation, the diploid number is restored in the zygote (1)\n• Without meiosis, chromosome number would double with each generation (1)` },
      { q: 'Describe the process of differentiation in a zygote developing into a multicellular organism.', marks: 3, markScheme: `• The zygote divides by mitosis, initially producing identical cells (1)\n• As development proceeds, cells begin to express different genes in response to signalling molecules / positional information (1)\n• This leads to different cell types with specialised structures and functions (e.g. neurones, muscle cells, epithelial cells) (1)` },
      { q: 'Draw a labelled diagram showing crossing over during meiosis I.', marks: 3, diagram: true, markScheme: `• Homologous pair of chromosomes shown synapsed / as a bivalent (1)\n• Chiasma / point of crossover shown where non-sister chromatids exchange segments (1)\n• Resulting recombinant chromatids correctly shown with exchanged sections (1)` },
      { q: 'Explain why adult stem cells are more limited in their use than embryonic stem cells.', marks: 2, markScheme: `• Adult stem cells are multipotent, meaning they can only differentiate into a limited range of cell types within their tissue of origin (1)\n• Embryonic stem cells are pluripotent, so can become almost any cell type, making them more versatile for medical applications (1)` },
      { q: 'Outline the role of signalling molecules in determining cell fate during development.', marks: 3, markScheme: `• Signalling molecules / morphogens are produced by specific cells and diffuse to surrounding cells (1)\n• Different concentrations of signalling molecules activate different transcription factors (1)\n• This causes different genes to be expressed, directing cells to differentiate into specific cell types depending on their position (1)` },
      { q: 'Explain what is meant by the term genome.', marks: 1, markScheme: `• The entire set of DNA / genetic information in an organism, including all genes and non-coding sequences (1)` },
      { q: 'State why all cells in an organism contain the same genes but have different structures and functions.', marks: 2, markScheme: `• All cells arise from the same zygote by mitosis, so they have identical DNA (1)\n• Different genes are expressed in different cell types due to differential gene expression / regulation (1)` },
      { q: 'Explain how induced pluripotent stem cells (iPS cells) are produced and why they are significant.', marks: 4, markScheme: `• Adult differentiated cells (e.g. skin cells) are reprogrammed by introducing specific transcription factors / genes (1)\n• These factors reset the gene expression pattern, returning the cell to a pluripotent state (1)\n• iPS cells can differentiate into many cell types, similar to embryonic stem cells (1)\n• They are significant because they avoid the ethical issues of using embryos and can be patient-specific, reducing immune rejection (1)` },
      { q: 'Describe how the lac operon is regulated in bacteria.', marks: 4, markScheme: `• In the absence of lactose, a repressor protein binds to the operator region, blocking RNA polymerase from transcribing the structural genes (1)\n• When lactose is present, it binds to the repressor and changes its shape so it can no longer bind the operator (1)\n• RNA polymerase can now transcribe the structural genes for lactose metabolism (1)\n• This is an example of gene regulation in prokaryotes by induction (1)` },
      { q: 'Explain the difference between benign and malignant tumours.', marks: 2, markScheme: `• Benign tumours grow slowly, are encapsulated, and do not invade surrounding tissues or spread to other parts of the body (1)\n• Malignant tumours grow rapidly, invade surrounding tissues, and can metastasise (spread) via the blood or lymphatic system to form secondary tumours (1)` },
      { q: 'Describe how X-inactivation demonstrates epigenetic gene regulation.', marks: 3, markScheme: `• In female mammals, one X chromosome in each cell is randomly inactivated early in development (1)\n• The inactivated X is heavily methylated and condensed into a Barr body, preventing gene expression (1)\n• This is an epigenetic mechanism because the DNA sequence is unchanged but gene expression is altered; the pattern is maintained through cell divisions (1)` },
      { q: 'Suggest how knowledge of the cell cycle can be applied to cancer treatment.', marks: 3, markScheme: `• Chemotherapy drugs can target rapidly dividing cells by interfering with DNA replication (S phase) or mitosis (1)\n• Drugs that block specific checkpoints in the cell cycle can prevent cancer cells from dividing (1)\n• Understanding the molecular basis of cell cycle control helps in developing targeted therapies that act on specific mutated proteins (e.g. kinase inhibitors) (1)` },
      { q: 'Explain why organisms produced by cloning are genetically identical but may still show phenotypic variation.', marks: 2, markScheme: `• Clones have identical DNA / genotype (1)\n• Environmental factors and epigenetic differences (e.g. different methylation patterns) can cause differences in gene expression and therefore phenotype (1)` },
      { q: 'Describe the role of proto-oncogenes in normal cells and explain how they can become oncogenes.', marks: 3, markScheme: `• Proto-oncogenes code for proteins that stimulate cell division / promote progression through the cell cycle (1)\n• A mutation in a proto-oncogene can convert it to an oncogene, which is permanently active (1)\n• This leads to uncontrolled cell division and can contribute to tumour formation / cancer (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S4 */
  'S4': {
    name: 'Biodiversity and Natural Resources',
    questions: [
      { q: 'State what is meant by the term biodiversity.', marks: 1, markScheme: `• The variety of living organisms in an area, including diversity within species, between species, and of ecosystems (1)` },
      { q: 'State the formula for Simpson\u2019s index of diversity.', marks: 1, markScheme: `• D = 1 \u2013 \u03a3(n/N)\u00b2, where n = number of individuals of each species and N = total number of individuals (1)` },
      { q: 'Calculate Simpson\u2019s index of diversity for a habitat with 30 daisies, 20 buttercups and 50 grasses (N = 100).', marks: 3, markScheme: `• (n/N)\u00b2 for daisies = (30/100)\u00b2 = 0.09; buttercups = (20/100)\u00b2 = 0.04; grasses = (50/100)\u00b2 = 0.25 (1)\n• \u03a3(n/N)\u00b2 = 0.09 + 0.04 + 0.25 = 0.38 (1)\n• D = 1 \u2013 0.38 = 0.62 (1)` },
      { q: 'Explain what a Simpson\u2019s index value close to 1 indicates about a habitat.', marks: 2, markScheme: `• A value close to 1 indicates high biodiversity / high species diversity (1)\n• There are many species present with relatively even population sizes / no single species dominates (1)` },
      { q: 'Describe how to use a quadrat to estimate the abundance of plant species in a field.', marks: 4, markScheme: `• Place quadrats randomly in the area (e.g. using random number coordinates) (1)\n• Count the number of individuals of each species within each quadrat, or estimate percentage cover (1)\n• Repeat with multiple quadrats (at least 10) to obtain a representative sample (1)\n• Calculate mean number per quadrat and scale up: mean count \u00d7 (total area / quadrat area) to estimate total abundance (1)` },
      { q: 'Explain the difference between species richness and species evenness.', marks: 2, markScheme: `• Species richness is the number of different species present in an area (1)\n• Species evenness is the relative abundance of each species / how evenly individuals are distributed among the different species (1)` },
      { q: 'Describe the hierarchical classification system used in taxonomy.', marks: 3, markScheme: `• Organisms are grouped into increasingly specific categories: Domain, Kingdom, Phylum, Class, Order, Family, Genus, Species (1)\n• Organisms within the same group share more characteristics than those in different groups (1)\n• The binomial naming system gives each species a unique two-part name (genus + species) (1)` },
      { q: 'Explain why classification systems are updated as new evidence becomes available.', marks: 3, markScheme: `• Advances in molecular biology / DNA sequencing reveal evolutionary relationships not apparent from morphology alone (1)\n• Species previously grouped together by appearance may be reclassified if their DNA sequences show they are not closely related (1)\n• New species are discovered, and existing classifications need to accommodate them (1)` },
      { q: 'Describe the structure of a typical plant cell.', marks: 4, diagram: true, markScheme: `• Cellulose cell wall outside the cell membrane providing structural support (1)\n• Large permanent vacuole containing cell sap (water, sugars, pigments) maintaining turgor (1)\n• Chloroplasts containing chlorophyll for photosynthesis (1)\n• Nucleus, mitochondria, ribosomes, endoplasmic reticulum, and cell membrane also present (1)` },
      { q: 'Describe the structure of cellulose and explain how it is suited to its function.', marks: 4, markScheme: `• Cellulose is a polysaccharide made of beta-glucose monomers linked by 1,4-glycosidic bonds (1)\n• Every other glucose molecule is inverted / rotated 180\u00b0, forming straight unbranched chains (1)\n• Chains are held together by hydrogen bonds between adjacent chains, forming microfibrils (1)\n• Microfibrils provide high tensile strength, making cellulose ideal for cell walls (1)` },
      { q: 'Compare the structures of starch and cellulose.', marks: 4, markScheme: `• Starch is made of alpha-glucose; cellulose is made of beta-glucose (1)\n• Starch (amylose) forms helical chains; cellulose forms straight chains (1)\n• Starch is a storage polysaccharide; cellulose is a structural polysaccharide (1)\n• Cellulose has hydrogen bonds between parallel chains forming microfibrils; starch does not form microfibrils (1)` },
      { q: 'Explain why starch is a good storage molecule.', marks: 3, markScheme: `• Insoluble, so does not affect water potential / osmosis in cells (1)\n• Compact / coiled structure allows large amounts to be stored in a small space (1)\n• Easily hydrolysed to release alpha-glucose for respiration when needed (1)` },
      { q: 'Describe how plant fibres are used by humans.', marks: 3, markScheme: `• Paper is made from wood pulp (cellulose fibres from trees) (1)\n• Rope and textiles can be made from plant fibres such as hemp, flax, or cotton (1)\n• Building materials (e.g. straw bales, bamboo) use plant fibres for structural support (1)` },
      { q: 'Explain the importance of maintaining biodiversity.', marks: 4, markScheme: `• Biodiversity provides ecosystem services such as pollination, water purification, and nutrient cycling (1)\n• Greater biodiversity increases ecosystem stability / resilience to change (1)\n• Potential sources of new medicines, food crops, and industrial materials may be lost if species go extinct (1)\n• Ethical / aesthetic reasons: many people believe all species have a right to exist / biodiversity has intrinsic value (1)` },
      { q: 'Describe how deforestation reduces biodiversity.', marks: 3, markScheme: `• Habitat destruction removes the living space and food sources for many species (1)\n• Specialist species that depend on the forest habitat may become extinct (1)\n• Fragmentation of remaining habitat isolates populations, reducing gene flow and genetic diversity (1)` },
      { q: 'Explain what is meant by sustainability and why it is important for natural resources.', marks: 3, markScheme: `• Sustainability means using resources at a rate that does not deplete them / meets the needs of the present without compromising future generations (1)\n• Natural resources such as timber, fish stocks, and freshwater are finite and can be exhausted if overexploited (1)\n• Sustainable management ensures long-term availability of resources and maintains ecosystem function (1)` },
      { q: 'Describe how coppicing is an example of sustainable woodland management.', marks: 3, markScheme: `• Coppicing involves cutting tree stems close to the ground to stimulate new growth from the stump (1)\n• Trees regrow from the base, providing a renewable source of timber without killing the tree (1)\n• The cycle of cutting and regrowth maintains habitat diversity and supports biodiversity (1)` },
      { q: 'Explain the role of zoos and seed banks in conservation.', marks: 4, markScheme: `• Zoos maintain captive breeding programmes for endangered species, maintaining genetic diversity (1)\n• Zoos also carry out education and research that supports conservation efforts (1)\n• Seed banks store seeds of plant species under controlled conditions (low temperature, low humidity) to preserve genetic material (1)\n• Both provide insurance against extinction in the wild and can be used for reintroduction or habitat restoration programmes (1)` },
      { q: 'Describe how a transect can be used to investigate the distribution of organisms across an environmental gradient.', marks: 3, markScheme: `• A line or belt transect is laid across the area of interest (e.g. from a path into a field) (1)\n• Quadrats are placed at regular intervals along the transect (1)\n• The species present and their abundance are recorded at each point, and data is plotted against distance to show changes in distribution (1)` },
      { q: 'Explain the difference between in situ and ex situ conservation.', marks: 2, markScheme: `• In situ conservation protects species in their natural habitat (e.g. nature reserves, marine protected areas) (1)\n• Ex situ conservation protects species outside their natural habitat (e.g. zoos, botanic gardens, seed banks) (1)` },
      { q: 'Evaluate the use of monocultures in agriculture.', marks: 5, markScheme: `• Advantage: efficient to plant, manage, and harvest a single crop using mechanisation (1)\n• Advantage: can maximise yield of a high-demand crop (1)\n• Disadvantage: reduces biodiversity by replacing diverse habitats with a single species (1)\n• Disadvantage: increases vulnerability to pests and diseases, requiring more pesticide use (1)\n• Evaluation: while economically beneficial in the short term, monocultures can degrade soil, reduce biodiversity, and require unsustainable inputs of fertilisers and pesticides (1)` },
      { q: 'Describe the structure of starch, including amylose and amylopectin.', marks: 3, markScheme: `• Starch is a mixture of amylose and amylopectin, both made from alpha-glucose (1)\n• Amylose is an unbranched helix with 1,4-glycosidic bonds (1)\n• Amylopectin is branched with 1,4-glycosidic bonds and 1,6-glycosidic bonds at branch points (1)` },
      { q: 'Explain why the test for starch uses iodine and describe the expected result.', marks: 2, markScheme: `• Iodine solution (iodine in potassium iodide) is added to the sample (1)\n• If starch is present, the solution turns blue-black because iodine molecules fit inside the amylose helix (1)` },
      { q: 'Draw a labelled diagram showing the structure of a cellulose microfibril.', marks: 3, diagram: true, markScheme: `• Individual beta-glucose chains shown as straight, parallel strands (1)\n• Hydrogen bonds between adjacent chains shown / indicated (1)\n• Multiple chains grouped together to form a microfibril, labelled correctly (1)` },
      { q: 'Explain how mark-release-recapture is used to estimate population size and state one assumption.', marks: 4, markScheme: `• A sample of organisms is captured, counted, marked, and released (1)\n• After a suitable time period, a second sample is captured and the number of marked individuals is counted (1)\n• Population estimate = (number in first sample \u00d7 number in second sample) / number of marked recaptures (Lincoln index) (1)\n• Assumption: no immigration, emigration, births, or deaths between samples / marking does not affect behaviour or survival (1)` },
      { q: 'Describe how a chi-squared test can be used to test whether observed species distributions differ from expected.', marks: 3, markScheme: `• Calculate expected frequencies based on the null hypothesis (e.g. even distribution) (1)\n• Use the formula \u03c7\u00b2 = \u03a3 (O \u2013 E)\u00b2 / E for each category (1)\n• Compare the calculated \u03c7\u00b2 value with the critical value at p = 0.05 and the appropriate degrees of freedom; if \u03c7\u00b2 exceeds the critical value, reject the null hypothesis (1)` },
      { q: 'Explain why genetic diversity within a species is important for its survival.', marks: 3, markScheme: `• Genetic diversity provides a range of alleles within the population (1)\n• If environmental conditions change, some individuals may have alleles that confer a survival advantage (1)\n• This allows the population to adapt through natural selection, reducing the risk of extinction (1)` },
      { q: 'Describe how habitat destruction and climate change threaten biodiversity.', marks: 4, markScheme: `• Habitat destruction removes the environment species depend on for food, shelter and reproduction (1)\n• Climate change alters temperature and rainfall patterns, affecting species distribution and food availability (1)\n• Species unable to migrate or adapt quickly enough may decline or go extinct (1)\n• Both factors can interact: climate change may make fragmented habitats even less suitable for resident species (1)` },
      { q: 'Outline the role of international agreements in biodiversity conservation.', marks: 3, markScheme: `• Agreements such as CITES restrict international trade in endangered species and their products (1)\n• The Convention on Biological Diversity sets targets for countries to protect biodiversity and manage resources sustainably (1)\n• International cooperation is necessary because biodiversity loss is a global issue; species and ecosystems cross national boundaries (1)` },
      { q: 'Explain why endemic species on islands are particularly vulnerable to extinction.', marks: 3, markScheme: `• Island species often have small population sizes and limited geographical range (1)\n• They may have evolved in the absence of predators and therefore lack defences against introduced species (1)\n• Habitat destruction on a small island can eliminate a large proportion of the species\u2019 total habitat (1)` },
      { q: 'Describe how to test a plant tissue sample for the presence of reducing sugars and non-reducing sugars.', marks: 4, markScheme: `• Add Benedict\u2019s reagent to the sample and heat in a water bath at approximately 80\u00b0C for 2\u20133 minutes (1)\n• If reducing sugars are present, the solution changes from blue to green/yellow/orange/brick red (1)\n• If the Benedict\u2019s test is negative, hydrolyse the sample by adding dilute HCl and heating, then neutralise with NaHCO\u2083 (1)\n• Repeat the Benedict\u2019s test; a positive result now indicates non-reducing sugars were present (e.g. sucrose) (1)` },
      { q: 'Explain the role of keystone species in maintaining ecosystem stability.', marks: 3, markScheme: `• A keystone species has a disproportionately large effect on its ecosystem relative to its abundance (1)\n• Removal of a keystone species can cause significant changes to ecosystem structure, e.g. trophic cascades (1)\n• Examples: top predators controlling herbivore populations, or pollinators essential for plant reproduction (1)` },
      { q: 'Describe the differences between prokaryotic and eukaryotic cells.', marks: 4, markScheme: `• Prokaryotes have no membrane-bound nucleus; eukaryotes have a membrane-bound nucleus containing chromosomes (1)\n• Prokaryotes have smaller ribosomes (70S) than eukaryotes (80S) (1)\n• Prokaryotes lack membrane-bound organelles (no mitochondria, ER, Golgi); eukaryotes have these (1)\n• Prokaryotic DNA is circular and found in the nucleoid; eukaryotic DNA is linear and associated with histone proteins (1)` },
      { q: 'Explain why scientists use the three-domain system of classification.', marks: 2, markScheme: `• Molecular evidence (ribosomal RNA sequences) shows that organisms fall into three distinct evolutionary groups: Bacteria, Archaea, and Eukarya (1)\n• The previous five-kingdom system grouped Archaea with Bacteria, but molecular data shows they are more different from each other than previously thought (1)` },
      { q: 'Calculate the estimated population size using the Lincoln index: first sample = 40, second sample = 50, recaptured marked = 10.', marks: 2, markScheme: `• N = (40 \u00d7 50) / 10 (1)\n• N = 200 (1)` },
      { q: 'Describe the structure of a chloroplast and explain how it is adapted for photosynthesis.', marks: 4, diagram: true, markScheme: `• Double membrane / envelope surrounding the organelle (1)\n• Internal membrane system of thylakoids arranged in stacks called grana, where the light-dependent reactions occur (1)\n• Thylakoid membranes contain photosynthetic pigments (chlorophyll) and electron carriers (1)\n• Stroma is the fluid-filled matrix where the light-independent reactions (Calvin cycle) occur, containing enzymes including RuBisCO (1)` },
      { q: 'Describe the role of cellulose in plant cell walls.', marks: 2, markScheme: `• Cellulose microfibrils provide tensile strength to the cell wall, preventing the cell from bursting when turgid (1)\n• The cell wall maintains cell shape and provides structural support for the whole plant (1)` },
      { q: 'Explain how natural selection can lead to changes in the frequency of alleles in a population.', marks: 4, markScheme: `• Variation exists within a population due to genetic differences / different alleles (1)\n• Individuals with alleles that confer a selective advantage in the current environment are more likely to survive and reproduce (1)\n• These advantageous alleles are passed on to the next generation at a higher frequency (1)\n• Over many generations, the frequency of the advantageous allele increases in the population (1)` },
      { q: 'Suggest why maintaining genetic diversity in crop plants is important for food security.', marks: 3, markScheme: `• Genetic diversity provides a range of alleles that may confer resistance to new diseases or pests (1)\n• It allows crops to be bred for adaptation to changing environmental conditions (e.g. drought, higher temperatures) (1)\n• Over-reliance on genetically uniform crop varieties increases vulnerability to widespread crop failure (1)` },
      { q: 'Describe how to carry out the iodine test for starch and the emulsion test for lipids.', marks: 3, markScheme: `• Iodine test: add iodine solution to the sample; a colour change from yellow-brown to blue-black indicates starch is present (1)\n• Emulsion test: dissolve the sample in ethanol, then pour into water (1)\n• A cloudy white emulsion indicates lipids are present (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S5 */
  'S5': {
    name: 'On the Wild Side',
    questions: [
      { q: 'State the word equation for photosynthesis.', marks: 1, markScheme: `• Carbon dioxide + water \u2192 glucose + oxygen (in the presence of light energy) (1)` },
      { q: 'State where the light-dependent reactions of photosynthesis take place.', marks: 1, markScheme: `• On the thylakoid membranes (of the grana) in the chloroplast (1)` },
      { q: 'State where the light-independent reactions (Calvin cycle) take place.', marks: 1, markScheme: `• In the stroma of the chloroplast (1)` },
      { q: 'Describe the light-dependent reactions of photosynthesis.', marks: 5, markScheme: `• Light energy is absorbed by chlorophyll and other photosynthetic pigments (1)\n• Electrons in chlorophyll are excited to a higher energy level and pass along the electron transport chain (1)\n• The energy released is used to pump H\u207a ions across the thylakoid membrane, creating a proton gradient (1)\n• H\u207a ions flow back through ATP synthase, driving the synthesis of ATP by chemiosmosis (1)\n• Water is photolysed (split) to provide replacement electrons, H\u207a ions, and O\u2082 as a by-product; NADP is reduced to NADPH (1)` },
      { q: 'Describe the Calvin cycle.', marks: 5, markScheme: `• CO\u2082 is fixed by combining with ribulose bisphosphate (RuBP, 5C) catalysed by RuBisCO (1)\n• This produces an unstable 6C compound that immediately splits into two molecules of glycerate-3-phosphate (GP, 3C) (1)\n• GP is reduced to glyceraldehyde-3-phosphate (GALP / G3P, 3C) using ATP and NADPH from the light-dependent reactions (1)\n• Some GALP is used to regenerate RuBP using ATP (1)\n• Some GALP is used to synthesise glucose and other organic molecules (1)` },
      { q: 'Explain the role of RuBisCO in the Calvin cycle.', marks: 2, markScheme: `• RuBisCO is the enzyme that catalyses the fixation of CO\u2082 by combining it with RuBP (1)\n• This is the first step / carbon fixation step of the Calvin cycle, producing two molecules of GP (1)` },
      { q: 'Explain how energy is transferred through an ecosystem.', marks: 4, markScheme: `• Producers (plants/autotrophs) convert light energy into chemical energy via photosynthesis (1)\n• Primary consumers obtain energy by eating producers; secondary consumers eat primary consumers, and so on (1)\n• Energy is transferred from one trophic level to the next through feeding (1)\n• Energy is lost at each trophic level through respiration (heat), excretion, and in uneaten parts, so less is available at higher trophic levels (1)` },
      { q: 'Explain why energy transfer between trophic levels is inefficient.', marks: 3, markScheme: `• Not all biomass is consumed / some parts (roots, bones) are not eaten (1)\n• Not all consumed biomass is assimilated / some is lost in faeces (1)\n• A significant proportion of assimilated energy is lost as heat through respiration (1)` },
      { q: 'State the equation for net primary productivity (NPP).', marks: 1, markScheme: `• NPP = GPP \u2013 R, where GPP is gross primary productivity and R is respiratory losses by the plant (1)` },
      { q: 'Calculate the net primary productivity if GPP is 20,000 kJ/m\u00b2/year and plant respiration uses 12,000 kJ/m\u00b2/year.', marks: 2, markScheme: `• NPP = GPP \u2013 R = 20,000 \u2013 12,000 (1)\n• = 8,000 kJ/m\u00b2/year (1)` },
      { q: 'Describe the stages of ecological succession.', marks: 4, markScheme: `• Pioneer species (e.g. lichens, mosses) colonise bare/inhospitable substrate first (1)\n• They modify the environment (e.g. weathering rock, adding organic matter) making it more suitable for other species (1)\n• Each seral stage / community is replaced by the next as conditions change, increasing biodiversity and soil depth (1)\n• Eventually a climax community is established, which is stable and self-sustaining (1)` },
      { q: 'Explain the difference between primary and secondary succession.', marks: 2, markScheme: `• Primary succession occurs on previously uncolonised substrate with no soil (e.g. bare rock, lava, sand dunes) (1)\n• Secondary succession occurs on substrate where a community previously existed but was disturbed (e.g. after fire or clearing); soil and seed bank are already present (1)` },
      { q: 'Describe the carbon cycle, including the roles of photosynthesis, respiration, and decomposition.', marks: 5, diagram: true, markScheme: `• Photosynthesis removes CO\u2082 from the atmosphere and incorporates carbon into organic molecules in plants (1)\n• Respiration by all organisms releases CO\u2082 back into the atmosphere (1)\n• Feeding transfers carbon through food chains from producers to consumers (1)\n• Decomposition by microorganisms breaks down dead organic matter, releasing CO\u2082 through respiration (1)\n• Combustion of fossil fuels releases stored carbon as CO\u2082 into the atmosphere (1)` },
      { q: 'Explain how the burning of fossil fuels contributes to the enhanced greenhouse effect.', marks: 3, markScheme: `• Burning fossil fuels releases CO\u2082 that was locked away in geological stores (1)\n• Increased atmospheric CO\u2082 absorbs more infrared radiation re-emitted from the Earth\u2019s surface (1)\n• This traps more heat in the atmosphere, raising global temperatures / enhanced greenhouse effect (1)` },
      { q: 'Evaluate the evidence for human-caused climate change.', marks: 6, markScheme: `• Ice core data shows a strong correlation between CO\u2082 levels and global temperature over hundreds of thousands of years (1)\n• Since the Industrial Revolution, atmospheric CO\u2082 has risen sharply, correlating with increased fossil fuel use (1)\n• Global average temperatures have risen significantly over the last century, consistent with greenhouse gas increases (1)\n• However, natural climate variation (solar activity, volcanic eruptions) also affects temperature (1)\n• The scientific consensus (IPCC) is that human activities are the dominant cause of observed warming since the mid-20th century (1)\n• Some uncertainty remains in climate models, but the weight of evidence strongly supports anthropogenic climate change (1)` },
      { q: 'Describe the evidence for evolution provided by the fossil record.', marks: 3, markScheme: `• Fossils show a progression from simple organisms in older rock layers to more complex organisms in younger layers (1)\n• Transitional fossils (e.g. Archaeopteryx) show intermediate features between groups, suggesting common ancestry (1)\n• The sequence of fossils in rock strata is consistent with the theory that species change over time through natural selection (1)` },
      { q: 'Describe the evidence for evolution provided by comparative anatomy.', marks: 3, markScheme: `• Homologous structures (e.g. pentadactyl limb in mammals) have the same basic structure but different functions (1)\n• This suggests descent from a common ancestor with subsequent adaptation to different environments (1)\n• Vestigial structures (e.g. appendix in humans, pelvic bones in whales) indicate evolutionary loss of function over time (1)` },
      { q: 'Explain how molecular evidence (DNA and protein comparisons) supports the theory of evolution.', marks: 3, markScheme: `• Closely related species have more similar DNA base sequences / amino acid sequences than distantly related species (1)\n• The degree of difference in sequences is proportional to the time since species diverged from a common ancestor (molecular clock) (1)\n• Universal features such as DNA and the genetic code support common ancestry of all life (1)` },
      { q: 'Explain the biological consequences of climate change for organisms.', marks: 4, markScheme: `• Changes in distribution: species may shift their range towards the poles or to higher altitudes (1)\n• Changes in phenology: timing of seasonal events (migration, flowering, breeding) may shift (1)\n• Some species may be unable to adapt and face increased risk of extinction (1)\n• Changes in species interactions: mismatches between predators and prey, or pollinators and plants (1)` },
      { q: 'Calculate the percentage efficiency of energy transfer from primary producers to primary consumers if NPP is 8000 kJ/m\u00b2/year and energy in primary consumers is 800 kJ/m\u00b2/year.', marks: 2, markScheme: `• Efficiency = (energy available at next trophic level / energy available at previous trophic level) \u00d7 100 (1)\n• = (800 / 8000) \u00d7 100 = 10% (1)` },
      { q: 'Describe how chromatography can be used to separate photosynthetic pigments.', marks: 4, markScheme: `• Extract pigments from leaves by grinding with a solvent (e.g. acetone or propanone) (1)\n• Apply a concentrated spot of the extract onto chromatography paper / thin-layer chromatography plate near the bottom (1)\n• Place in a solvent (running solvent) ensuring the spot is above the solvent level (1)\n• Pigments separate based on their solubility in the solvent; calculate Rf values to identify each pigment (1)` },
      { q: 'Explain why a food chain usually has no more than four or five trophic levels.', marks: 2, markScheme: `• Energy is lost at each trophic level (mainly through respiration as heat) (1)\n• By the fourth or fifth level, there is insufficient energy remaining to support another population / trophic level (1)` },
      { q: 'Describe how to measure net primary productivity in a terrestrial ecosystem.', marks: 3, markScheme: `• Harvest and dry plant biomass from a known area at the start and end of a time period (1)\n• The increase in dry biomass per unit area per unit time gives an estimate of NPP (1)\n• Alternatively, measure GPP (e.g. using CO\u2082 uptake) and subtract plant respiration (measured in the dark) (1)` },
      { q: 'Draw and label a diagram of the Calvin cycle, showing the key molecules involved.', marks: 4, diagram: true, markScheme: `• CO\u2082 entering and combining with RuBP (5C) shown, catalysed by RuBisCO (1)\n• Formation of GP (3C) shown (1)\n• Reduction of GP to GALP (3C) using ATP and NADPH indicated (1)\n• Regeneration of RuBP from GALP using ATP shown, with some GALP leaving the cycle for glucose synthesis (1)` },
      { q: 'Explain the role of decomposers in nutrient cycling.', marks: 3, markScheme: `• Decomposers (bacteria and fungi) break down dead organic matter and waste products (1)\n• They secrete extracellular enzymes that digest complex organic molecules into simpler inorganic molecules (1)\n• This releases mineral ions (e.g. nitrates, phosphates) back into the soil, making them available for uptake by plant roots (1)` },
      { q: 'Explain the greenhouse effect and distinguish it from the enhanced greenhouse effect.', marks: 4, markScheme: `• The natural greenhouse effect: greenhouse gases (CO\u2082, methane, water vapour) absorb infrared radiation re-emitted from the Earth and re-radiate it back, warming the atmosphere (1)\n• This is a natural process essential for maintaining Earth\u2019s temperature suitable for life (1)\n• The enhanced greenhouse effect: human activities have increased concentrations of greenhouse gases (1)\n• This traps more infrared radiation, causing global temperatures to rise above natural levels (1)` },
      { q: 'Describe how deforestation affects the carbon cycle.', marks: 3, markScheme: `• Trees are a carbon sink; removing them reduces the amount of CO\u2082 absorbed from the atmosphere by photosynthesis (1)\n• Burning or decomposition of felled trees releases stored carbon as CO\u2082 (1)\n• Soil carbon may also be released as decomposition increases when vegetation cover is removed (1)` },
      { q: 'Explain how photosynthetic pigments absorb light of different wavelengths.', marks: 3, markScheme: `• Different pigments (chlorophyll a, chlorophyll b, carotenoids) absorb light at different wavelengths (1)\n• Chlorophyll a absorbs mainly red and blue light; chlorophyll b and carotenoids absorb slightly different wavelengths (1)\n• Having multiple pigments allows the plant to absorb a wider range of wavelengths, maximising light energy capture for photosynthesis (1)` },
      { q: 'Explain the role of NADP in photosynthesis.', marks: 2, markScheme: `• In the light-dependent reactions, NADP is reduced to NADPH by accepting electrons and H\u207a ions (1)\n• NADPH carries the reducing power to the Calvin cycle, where it is used to reduce GP to GALP (1)` },
      { q: 'Describe how a limiting factor affects the rate of photosynthesis.', marks: 3, markScheme: `• A limiting factor is the factor present at the lowest / least favourable level that restricts the rate of a process (1)\n• Increasing the limiting factor increases the rate of photosynthesis up to a point (1)\n• Beyond that point, another factor becomes limiting and the rate plateaus (e.g. light intensity, CO\u2082 concentration, temperature) (1)` },
      { q: 'Explain what is meant by the compensation point in relation to photosynthesis and respiration.', marks: 2, markScheme: `• The compensation point is the light intensity at which the rate of photosynthesis equals the rate of respiration (1)\n• At this point, there is no net gas exchange; CO\u2082 absorbed by photosynthesis equals CO\u2082 released by respiration (1)` },
      { q: 'Describe how data loggers and sensors can be used to measure abiotic factors in an ecosystem.', marks: 3, markScheme: `• Data loggers connected to sensors can continuously record abiotic factors such as temperature, light intensity, humidity, and soil moisture (1)\n• They record measurements at set time intervals over extended periods (1)\n• Data can be downloaded to a computer for analysis, providing accurate and objective measurements with minimal human error (1)` },
      { q: 'Draw a labelled diagram showing the flow of energy through a simple food chain, including energy losses.', marks: 4, diagram: true, markScheme: `• Producers shown receiving light energy and converting to chemical energy via photosynthesis (1)\n• Energy transfer arrows from producers to primary consumers to secondary consumers (1)\n• Energy losses at each trophic level labelled: respiration (heat), faeces, uneaten biomass (1)\n• Decomposers shown receiving energy from dead organisms and waste at all trophic levels (1)` },
      { q: 'Explain how natural selection leads to adaptation of populations to their environment.', marks: 4, markScheme: `• Genetic variation exists in a population due to mutations and sexual reproduction (1)\n• Environmental pressures (predation, disease, competition) create a selection pressure (1)\n• Organisms with advantageous phenotypes are more likely to survive, reproduce, and pass on their alleles (1)\n• Over generations, the frequency of advantageous alleles increases, and the population becomes better adapted to its environment (1)` },
      { q: 'Suggest how rising global temperatures could affect food webs in the Arctic.', marks: 3, markScheme: `• Melting sea ice reduces habitat for species such as polar bears and seals (1)\n• Changes in plankton populations at the base of food webs affect all higher trophic levels (1)\n• Altered migration patterns and species distribution could lead to new competitive and predator-prey interactions (1)` },
      { q: 'Explain the concept of carbon neutrality and why burning biomass is sometimes considered carbon neutral.', marks: 3, markScheme: `• Carbon neutrality means no net increase in atmospheric CO\u2082 (1)\n• Burning biomass releases CO\u2082, but the same amount was absorbed by the plant during photosynthesis during its lifetime (1)\n• However, this only holds if the biomass is replaced at the same rate it is burned; in practice, emissions from processing and transport mean it may not be truly carbon neutral (1)` },
      { q: 'Explain how speciation occurs through geographical isolation.', marks: 4, markScheme: `• A population is divided by a geographical barrier (e.g. mountain range, river, island formation) (1)\n• The separated populations experience different selection pressures / environmental conditions (1)\n• Different mutations arise and are selected for in each population, leading to genetic divergence (1)\n• Over time, the populations become so genetically different that they can no longer interbreed to produce fertile offspring / they are now separate species (allopatric speciation) (1)` },
      { q: 'Describe how peat bogs act as carbon stores and why their destruction is a concern.', marks: 3, markScheme: `• Peat bogs form in waterlogged, acidic conditions where decomposition is very slow (1)\n• Dead plant material accumulates over thousands of years, locking carbon in the peat (1)\n• Draining or burning peat bogs releases this stored carbon as CO\u2082, contributing to atmospheric greenhouse gas levels (1)` },
      { q: 'Explain the difference between photosystem I and photosystem II.', marks: 3, markScheme: `• Photosystem II (PSII) absorbs light at 680 nm and is involved in the photolysis of water, releasing electrons, H\u207a ions, and O\u2082 (1)\n• Photosystem I (PSI) absorbs light at 700 nm and passes excited electrons to NADP\u207a reductase to reduce NADP\u207a to NADPH (1)\n• Electrons flow from PSII through the electron transport chain to PSI in non-cyclic photophosphorylation (1)` },
      { q: 'Explain what is meant by the term biomass and how it is measured.', marks: 2, markScheme: `• Biomass is the total mass of living material / organic matter in an organism or at a trophic level (1)\n• It is measured as dry mass (by drying to constant weight) per unit area, which removes variable water content (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S6 */
  'S6': {
    name: 'Immunity, Infection and Forensics',
    questions: [
      { q: 'State what is meant by the term pathogen.', marks: 1, markScheme: `• A microorganism that causes disease (1)` },
      { q: 'State three types of pathogen and give an example of a disease caused by each.', marks: 3, markScheme: `• Bacteria, e.g. tuberculosis / cholera / MRSA (1)\n• Virus, e.g. influenza / HIV / COVID-19 (1)\n• Fungi, e.g. athlete\u2019s foot / ringworm / Pneumocystis (1)` },
      { q: 'Describe how bacteria cause disease.', marks: 3, markScheme: `• Bacteria reproduce rapidly inside the body by binary fission (1)\n• They produce toxins that damage cells and tissues (1)\n• Some bacteria directly invade and destroy host cells / interfere with normal cell function (1)` },
      { q: 'Describe how viruses cause disease.', marks: 3, markScheme: `• Viruses invade host cells and use the host\u2019s cellular machinery to replicate (1)\n• New virus particles are assembled inside the host cell (1)\n• The host cell may burst (lysis), releasing new viruses that infect other cells, causing cell damage and disease symptoms (1)` },
      { q: 'Describe the body\u2019s non-specific / innate immune defences.', marks: 4, markScheme: `• Skin acts as a physical barrier preventing entry of pathogens (1)\n• Mucous membranes in the respiratory and digestive tracts trap pathogens (1)\n• Stomach acid (low pH) kills many ingested pathogens (1)\n• Phagocytes (neutrophils, macrophages) engulf and destroy pathogens by phagocytosis (1)` },
      { q: 'Describe the process of phagocytosis.', marks: 4, markScheme: `• Phagocyte is attracted to the pathogen by chemicals released at the site of infection (chemotaxis) (1)\n• The phagocyte engulfs the pathogen by surrounding it with its cell membrane, forming a phagosome (1)\n• Lysosomes fuse with the phagosome, releasing hydrolytic enzymes that digest the pathogen (1)\n• Antigens from the digested pathogen are presented on the phagocyte\u2019s surface (antigen presentation) (1)` },
      { q: 'Explain the role of T lymphocytes in the adaptive immune response.', marks: 4, markScheme: `• T helper cells recognise antigens presented by phagocytes / antigen-presenting cells (1)\n• They release cytokines that activate B cells and other T cells (1)\n• T killer / cytotoxic cells recognise and destroy infected body cells by releasing perforin to create pores in the cell membrane (1)\n• T memory cells remain in the body and provide a faster response upon re-infection (1)` },
      { q: 'Explain the role of B lymphocytes in the adaptive immune response.', marks: 4, markScheme: `• B cells have antibodies on their surface that are specific to a particular antigen (1)\n• When activated (by binding to antigen and stimulation by T helper cells), B cells divide by mitosis / clonal expansion (1)\n• They differentiate into plasma cells that secrete large quantities of specific antibodies (1)\n• Memory B cells remain in the body and enable a faster, stronger secondary response upon re-exposure (1)` },
      { q: 'Draw and label a diagram of an antibody molecule.', marks: 3, diagram: true, markScheme: `• Y-shaped molecule with four polypeptide chains (two heavy, two light) shown (1)\n• Variable region at the tips of the Y labelled, showing the antigen-binding sites (1)\n• Constant region forming the stem of the Y labelled; disulfide bonds between chains indicated (1)` },
      { q: 'Explain how antibodies help to destroy pathogens.', marks: 4, markScheme: `• Antibodies bind to specific antigens on the surface of pathogens (1)\n• Agglutination: antibodies cause pathogens to clump together, making it easier for phagocytes to engulf them (1)\n• Neutralisation: antibodies block pathogen binding sites, preventing attachment to host cells (1)\n• Opsonisation: antibodies coat pathogens, enhancing recognition and phagocytosis (1)` },
      { q: 'Explain the difference between the primary and secondary immune response.', marks: 4, markScheme: `• The primary response occurs on first exposure to an antigen; it is slow because specific B and T cells must be selected and clonally expanded (1)\n• A small amount of antibody is produced after a lag period (1)\n• The secondary response occurs on re-exposure to the same antigen; it is faster and produces more antibodies (1)\n• Memory cells produced during the primary response enable the rapid secondary response (1)` },
      { q: 'Explain how vaccination provides immunity to a disease.', marks: 4, markScheme: `• A vaccine contains a weakened / inactivated / part of a pathogen (antigen) that does not cause disease (1)\n• The antigens stimulate the immune system to produce specific B and T cells (1)\n• Memory cells are produced that remain in the body long-term (1)\n• Upon subsequent exposure to the actual pathogen, a rapid secondary immune response occurs, destroying the pathogen before symptoms develop (1)` },
      { q: 'Explain the concept of herd immunity.', marks: 3, markScheme: `• Herd immunity occurs when a large proportion of a population is immune to a disease (through vaccination or prior infection) (1)\n• This reduces the likelihood of the pathogen spreading because there are fewer susceptible individuals (1)\n• It protects those who cannot be vaccinated (e.g. immunocompromised individuals, infants) (1)` },
      { q: 'Explain how antibiotic resistance develops in bacteria.', marks: 4, markScheme: `• Random mutations in bacterial DNA may give some bacteria resistance to an antibiotic (1)\n• When an antibiotic is used, susceptible bacteria are killed but resistant bacteria survive (1)\n• Resistant bacteria reproduce rapidly, passing on the resistance gene / allele to offspring (1)\n• Horizontal gene transfer (e.g. via plasmids / conjugation) can spread resistance between different bacterial species (1)` },
      { q: 'Evaluate the use of antibiotics in medicine and agriculture.', marks: 5, markScheme: `• Antibiotics have saved millions of lives by treating bacterial infections (1)\n• Overuse and misuse in medicine (e.g. prescribing for viral infections) has accelerated resistance (1)\n• Use in agriculture (e.g. in animal feed) has also contributed to resistance development (1)\n• MRSA and other resistant strains are increasingly difficult to treat (1)\n• Evaluation: antibiotics remain essential but must be used more responsibly; new antibiotics need to be developed and alternatives explored (1)` },
      { q: 'Describe how DNA profiling (genetic fingerprinting) is carried out.', marks: 5, markScheme: `• DNA is extracted from a sample (blood, saliva, tissue) (1)\n• Specific regions (short tandem repeats / STRs) are amplified using PCR (1)\n• The amplified fragments are separated by gel electrophoresis or capillary electrophoresis (1)\n• The pattern of bands / peaks represents the individual\u2019s DNA profile (1)\n• Profiles are compared between samples to determine a match (1)` },
      { q: 'Explain why DNA profiling is useful in forensic science.', marks: 3, markScheme: `• Every individual (except identical twins) has a unique DNA profile based on STR lengths (1)\n• DNA from crime scene evidence can be compared with suspect profiles to establish identity (1)\n• DNA profiling can also be used to establish paternity, identify victims, and solve cold cases (1)` },
      { q: 'Describe how forensic scientists estimate time of death using body temperature.', marks: 3, markScheme: `• Body temperature decreases after death at a roughly predictable rate (1)\n• Normal body temperature is approximately 37\u00b0C; rate of cooling depends on environmental temperature, body size, and clothing (1)\n• By measuring the current body temperature and knowing the ambient temperature, the time since death can be estimated using cooling curves / Henssge nomogram (1)` },
      { q: 'Describe how decomposition and insect succession can be used to estimate time of death.', marks: 4, markScheme: `• After death, the body undergoes stages of decomposition: fresh, bloat, active decay, advanced decay, dry/skeletal (1)\n• Different species of insects (especially blowflies) colonise the body at predictable stages (1)\n• Identification of insect species and their developmental stage (egg, larva, pupa, adult) gives information about time since death (1)\n• Environmental factors (temperature, humidity) affect the rate of decomposition and insect development and must be considered (1)` },
      { q: 'Explain how the degree of rigor mortis can help estimate time of death.', marks: 3, markScheme: `• After death, muscles stiffen due to cross-bridges forming between actin and myosin when ATP supply ceases (1)\n• Rigor mortis typically begins 1\u20132 hours after death, becomes fully established at 6\u201312 hours (1)\n• It then gradually disappears after 24\u201336 hours as enzymes break down the muscle proteins (1)` },
      { q: 'Explain the role of antigen-presenting cells in the immune response.', marks: 2, markScheme: `• After phagocytosis, antigen-presenting cells (e.g. macrophages, dendritic cells) display pathogen antigens on their surface using MHC proteins (1)\n• This is necessary for activation of T helper cells, which then coordinate the adaptive immune response (1)` },
      { q: 'Describe how monoclonal antibodies are produced.', marks: 4, markScheme: `• An animal (e.g. mouse) is injected with the target antigen, stimulating B cell production (1)\n• B cells are extracted from the spleen and fused with myeloma (tumour) cells to form hybridoma cells (1)\n• Hybridomas are screened for production of the desired antibody and selected clones are cultured (1)\n• The hybridoma cells divide indefinitely, producing large quantities of identical (monoclonal) antibodies (1)` },
      { q: 'Describe one use of monoclonal antibodies in medicine.', marks: 2, markScheme: `• Pregnancy tests: monoclonal antibodies specific to hCG are used on test strips to detect the hormone in urine (1)\n• OR Targeted cancer therapy: monoclonal antibodies bind to specific antigens on tumour cells, delivering drugs or triggering the immune system to destroy the cancer cells (1)` },
      { q: 'Explain why it is difficult to develop vaccines against some viruses such as influenza.', marks: 3, markScheme: `• Influenza virus has a high mutation rate, leading to frequent changes in surface antigens (antigenic drift and shift) (1)\n• Memory cells from previous infection or vaccination may not recognise the new strain (1)\n• New vaccines must be developed each year to match the currently circulating strains (1)` },
      { q: 'Explain the difference between active and passive immunity.', marks: 4, markScheme: `• Active immunity: the body produces its own antibodies in response to exposure to antigens (1)\n• It provides long-term protection because memory cells are produced (1)\n• Passive immunity: antibodies are received from an external source (e.g. mother to baby via breast milk, or injection of antibodies) (1)\n• It provides immediate but short-term protection because no memory cells are produced and the antibodies are eventually broken down (1)` },
      { q: 'Describe how the polymerase chain reaction (PCR) is used to amplify DNA.', marks: 4, markScheme: `• DNA is heated to approximately 95\u00b0C to denature / separate the two strands (1)\n• Temperature is lowered to approximately 55\u201360\u00b0C for primers to anneal to complementary sequences on each strand (1)\n• Temperature is raised to approximately 72\u00b0C for Taq polymerase to extend the primers by adding complementary nucleotides (1)\n• The cycle is repeated 25\u201330 times, doubling the DNA with each cycle to produce millions of copies (1)` },
      { q: 'Explain why Taq polymerase is used in PCR rather than a standard DNA polymerase.', marks: 2, markScheme: `• Taq polymerase is a thermostable enzyme isolated from Thermus aquaticus, a thermophilic bacterium (1)\n• It is not denatured at the high temperatures (95\u00b0C) required for DNA denaturation in PCR, so it remains functional throughout all cycles (1)` },
      { q: 'Describe how ELISA tests use antibodies to detect the presence of a specific protein.', marks: 4, markScheme: `• A sample is added to a well coated with antibodies specific to the target protein (antigen) (1)\n• If the target protein is present, it binds to the antibodies (1)\n• A secondary antibody linked to an enzyme is added, which binds to the target protein (1)\n• A substrate is added that the enzyme converts to a coloured product; colour intensity indicates the concentration of the target protein (1)` },
      { q: 'Explain why forensic evidence from multiple sources is more reliable than a single piece of evidence.', marks: 2, markScheme: `• Multiple independent sources of evidence (DNA, entomology, body temperature, witnesses) corroborate each other (1)\n• This reduces the chance of error from a single method and provides a more reliable estimate of events (1)` },
      { q: 'Describe how gastric contents can be used in forensic investigations.', marks: 2, markScheme: `• The degree of food digestion in the stomach can help estimate the time of the last meal and therefore time of death (1)\n• Type of food present can help establish the victim\u2019s movements or confirm witness statements (1)` },
      { q: 'Explain how autoimmune diseases arise and give one example.', marks: 3, markScheme: `• In autoimmune diseases, the immune system fails to distinguish self from non-self and attacks the body\u2019s own cells/tissues (1)\n• T cells or antibodies target self-antigens on healthy cells (1)\n• Example: Type 1 diabetes (immune system destroys insulin-producing beta cells) / rheumatoid arthritis / multiple sclerosis / lupus (1)` },
      { q: 'Explain the role of cytokines in the immune response.', marks: 3, markScheme: `• Cytokines are signalling molecules / proteins released by immune cells (1)\n• They coordinate the immune response by stimulating cell division, differentiation, and activation of other immune cells (1)\n• Examples: interleukins (communication between leukocytes), interferons (antiviral defence), TNF (inflammation and apoptosis of infected cells) (1)` },
      { q: 'Describe how forensic entomologists use blowfly larvae to estimate time of death.', marks: 3, diagram: true, markScheme: `• Blowflies are among the first insects to colonise a body after death, laying eggs within hours (1)\n• The developmental stage of larvae (instar stage) and their size indicate how long they have been feeding (1)\n• Using known development rates at specific temperatures, the minimum time since colonisation (and thus approximate time of death) can be estimated (1)` },
      { q: 'Evaluate the use of vaccination programmes.', marks: 5, markScheme: `• Vaccines have eradicated smallpox and nearly eradicated polio, demonstrating their effectiveness (1)\n• They protect vulnerable individuals through herd immunity (1)\n• They are cost-effective compared to treating disease (1)\n• Concerns include rare side effects and allergic reactions (1)\n• Evaluation: the benefits of vaccination greatly outweigh the risks for the vast majority of the population; misinformation about vaccines can reduce uptake and threaten herd immunity (1)` },
      { q: 'Explain how the structure of HIV makes it difficult to develop a vaccine.', marks: 3, markScheme: `• HIV has a high mutation rate due to the error-prone reverse transcriptase enzyme (1)\n• Surface antigens (e.g. gp120) change rapidly, making it difficult for antibodies to recognise the virus (1)\n• HIV also hides within host T helper cells, evading the immune system and making it difficult to target (1)` },
      { q: 'Describe how tuberculosis (TB) is transmitted and why it is difficult to control globally.', marks: 4, markScheme: `• TB is caused by Mycobacterium tuberculosis and is spread by airborne droplets from coughing / sneezing (1)\n• Overcrowded and poorly ventilated conditions increase transmission (1)\n• The BCG vaccine provides limited protection, and some TB strains are multi-drug resistant (MDR-TB) (1)\n• Poverty, lack of access to healthcare, and co-infection with HIV make TB difficult to control in many countries (1)` },
      { q: 'Explain why the overuse of antibiotics is a concern for public health.', marks: 3, markScheme: `• Overuse increases selection pressure, accelerating the evolution of antibiotic-resistant bacteria (1)\n• Resistant infections (e.g. MRSA, C. difficile) are harder and more expensive to treat, leading to increased morbidity and mortality (1)\n• Without new antibiotics, previously treatable infections could become life-threatening / return to pre-antibiotic era (1)` },
      { q: 'Outline the process of gel electrophoresis for separating DNA fragments.', marks: 3, markScheme: `• DNA fragments are loaded into wells in an agarose gel and an electric current is applied (1)\n• Negatively charged DNA migrates towards the positive electrode (1)\n• Smaller fragments travel further / faster through the gel, separating fragments by size (1)` },
      { q: 'Explain why fungi are classified as a separate kingdom from plants.', marks: 2, markScheme: `• Fungi are heterotrophs that feed by secreting extracellular enzymes and absorbing digested nutrients (saprotrophic nutrition), unlike plants which are autotrophic (1)\n• Fungal cell walls are made of chitin, not cellulose; fungi do not photosynthesise and store glycogen, not starch (1)` },
      { q: 'Describe how Koch\u2019s postulates are used to establish that a specific microorganism causes a specific disease.', marks: 4, markScheme: `• The microorganism must be found in all organisms suffering from the disease but not in healthy ones (1)\n• The microorganism must be isolated from a diseased organism and grown in pure culture (1)\n• The cultured microorganism must cause disease when introduced into a healthy host (1)\n• The same microorganism must be re-isolated from the newly infected host and shown to be identical to the original (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S7 */
  'S7': {
    name: 'Run for Your Life',
    questions: [
      { q: 'State the role of ATP in living cells.', marks: 1, markScheme: `• ATP is the immediate / universal energy currency of cells, providing energy for cellular processes (1)` },
      { q: 'State what is meant by the term aerobic respiration.', marks: 1, markScheme: `• The release of energy from organic molecules (usually glucose) in the presence of oxygen, producing CO\u2082 and water (1)` },
      { q: 'State the balanced equation for aerobic respiration.', marks: 1, markScheme: `• C\u2086H\u2081\u2082O\u2086 + 6O\u2082 \u2192 6CO\u2082 + 6H\u2082O (+ ATP/energy) (1)` },
      { q: 'Describe the process of glycolysis.', marks: 4, markScheme: `• Glycolysis occurs in the cytoplasm (1)\n• Glucose (6C) is phosphorylated using 2 ATP to form fructose bisphosphate (1)\n• Fructose bisphosphate is split into two molecules of triose phosphate (3C) (1)\n• Each triose phosphate is oxidised to pyruvate (3C), producing a net gain of 2 ATP and 2 reduced NAD (NADH) (1)` },
      { q: 'Describe the link reaction.', marks: 3, markScheme: `• Pyruvate (3C) is transported into the mitochondrial matrix (1)\n• Pyruvate is decarboxylated (CO\u2082 removed) and dehydrogenated (hydrogen removed, reducing NAD to NADH) (1)\n• The resulting 2C acetyl group combines with coenzyme A to form acetyl CoA (1)` },
      { q: 'Describe the Krebs cycle.', marks: 5, markScheme: `• Acetyl CoA (2C) combines with oxaloacetate (4C) to form citrate (6C) (1)\n• Citrate is progressively decarboxylated and dehydrogenated through a series of reactions (1)\n• For each turn: 2 CO\u2082 are released, 3 NAD are reduced to NADH, and 1 FAD is reduced to FADH\u2082 (1)\n• 1 ATP is produced by substrate-level phosphorylation per turn (1)\n• Oxaloacetate (4C) is regenerated, allowing the cycle to continue (1)` },
      { q: 'Describe the electron transport chain and oxidative phosphorylation.', marks: 5, markScheme: `• NADH and FADH\u2082 donate electrons to electron carriers on the inner mitochondrial membrane (1)\n• Electrons pass along a series of carriers, releasing energy at each step (1)\n• This energy is used to pump H\u207a ions from the matrix into the intermembrane space, creating a proton gradient (1)\n• H\u207a ions flow back through ATP synthase by chemiosmosis, driving the synthesis of ATP (1)\n• Oxygen is the final electron acceptor, combining with electrons and H\u207a to form water (1)` },
      { q: 'Explain why oxygen is described as the final electron acceptor in aerobic respiration.', marks: 2, markScheme: `• At the end of the electron transport chain, oxygen accepts electrons and combines with H\u207a ions to form water (1)\n• Without oxygen, electrons cannot be removed from the chain, it stops functioning, and ATP production by oxidative phosphorylation ceases (1)` },
      { q: 'Describe anaerobic respiration in humans.', marks: 3, markScheme: `• In the absence of sufficient oxygen, pyruvate from glycolysis is converted to lactate (1)\n• This is catalysed by lactate dehydrogenase and involves the oxidation of NADH back to NAD (1)\n• This allows glycolysis to continue producing a small amount of ATP (net 2 per glucose) (1)` },
      { q: 'Explain the difference between anaerobic respiration in humans and in yeast.', marks: 2, markScheme: `• In humans, pyruvate is converted to lactate; in yeast, pyruvate is converted to ethanol and CO\u2082 (1)\n• In yeast, pyruvate is first decarboxylated to ethanal, then reduced to ethanol using NADH (1)` },
      { q: 'Describe the sliding filament model of muscle contraction.', marks: 6, markScheme: `• A nerve impulse triggers the release of calcium ions from the sarcoplasmic reticulum (1)\n• Ca\u00b2\u207a binds to troponin, causing tropomyosin to move and expose myosin-binding sites on actin (1)\n• Myosin heads bind to actin, forming cross-bridges (1)\n• The myosin head pivots / undergoes a power stroke, pulling the actin filament towards the centre of the sarcomere (using energy from ATP hydrolysis) (1)\n• ATP binds to the myosin head, causing it to detach from actin (1)\n• The myosin head is re-cocked using energy from ATP hydrolysis, ready to bind again; this cycle repeats, shortening the sarcomere (1)` },
      { q: 'Explain the role of ATP in muscle contraction.', marks: 3, markScheme: `• ATP provides energy for the power stroke / movement of the myosin head along actin (1)\n• ATP is needed to detach the myosin head from the actin binding site (1)\n• ATP powers the calcium ion pump that returns Ca\u00b2\u207a to the sarcoplasmic reticulum for muscle relaxation (1)` },
      { q: 'Explain why muscles require a rich blood supply.', marks: 3, markScheme: `• To deliver oxygen for aerobic respiration to produce ATP for muscle contraction (1)\n• To deliver glucose and other respiratory substrates (1)\n• To remove waste products such as CO\u2082 and lactate to prevent build-up / fatigue (1)` },
      { q: 'Draw and label a diagram of a sarcomere, identifying the A band, I band, H zone and Z lines.', marks: 4, diagram: true, markScheme: `• Z lines at each end of the sarcomere correctly shown and labelled (1)\n• A band (dark band) in the centre where thick (myosin) filaments are present, labelled (1)\n• I band (light band) either side of the Z line where only thin (actin) filaments are present, labelled (1)\n• H zone in the centre of the A band where only thick filaments are present, labelled (1)` },
      { q: 'Explain what happens to the I band and H zone during muscle contraction.', marks: 2, markScheme: `• The I band gets shorter / narrower because actin filaments slide over myosin towards the centre (1)\n• The H zone gets shorter / narrower because actin filaments overlap more with myosin; the A band stays the same width (1)` },
      { q: 'Describe the role of creatine phosphate in muscle cells.', marks: 2, markScheme: `• Creatine phosphate acts as a rapid reserve of phosphate groups for ATP regeneration (1)\n• It transfers a phosphate group to ADP to regenerate ATP very quickly during the first few seconds of intense exercise (1)` },
      { q: 'Explain the concept of oxygen debt (excess post-exercise oxygen consumption).', marks: 3, markScheme: `• During intense exercise, anaerobic respiration produces lactate (1)\n• After exercise, extra oxygen is consumed to oxidise lactate back to pyruvate in the liver (or convert it to glycogen) (1)\n• Additional oxygen is needed to replenish creatine phosphate stores, myoglobin oxygen stores, and restore resting metabolic conditions (1)` },
      { q: 'Explain why heart rate increases during exercise.', marks: 3, markScheme: `• Increased muscle activity increases demand for oxygen and glucose for aerobic respiration (1)\n• Chemoreceptors detect increased CO\u2082 / decreased pH in the blood and send signals to the cardiovascular centre in the medulla (1)\n• The medulla sends impulses via the sympathetic nervous system to the SAN, increasing heart rate to deliver more oxygenated blood to muscles (1)` },
      { q: 'Calculate the cardiac output if heart rate increases to 150 bpm and stroke volume is 80 cm\u00b3 during exercise.', marks: 2, markScheme: `• Cardiac output = heart rate \u00d7 stroke volume = 150 \u00d7 80 (1)\n• = 12,000 cm\u00b3/min / 12 dm\u00b3/min (1)` },
      { q: 'Explain how thermoregulation maintains a constant body temperature during exercise.', marks: 4, markScheme: `• Thermoreceptors detect the rise in blood temperature and send signals to the hypothalamus (1)\n• Vasodilation of arterioles near the skin surface increases blood flow to the skin, increasing heat loss by radiation (1)\n• Sweat glands produce more sweat; evaporation of sweat from the skin surface removes heat (1)\n• These are negative feedback mechanisms that bring body temperature back to the set point (1)` },
      { q: 'Explain the role of myoglobin in muscle tissue.', marks: 2, markScheme: `• Myoglobin is a protein in muscle cells that has a higher affinity for oxygen than haemoglobin (1)\n• It acts as an oxygen store, releasing oxygen to mitochondria during intense exercise when blood oxygen supply is insufficient (1)` },
      { q: 'Describe the structure of a mitochondrion and explain how its features are adapted for aerobic respiration.', marks: 4, diagram: true, markScheme: `• Double membrane: outer membrane is smooth, inner membrane is folded into cristae (1)\n• Cristae increase the surface area for the electron transport chain and ATP synthase (oxidative phosphorylation) (1)\n• Matrix contains enzymes for the Krebs cycle and the link reaction (1)\n• The intermembrane space is narrow, allowing a steep proton gradient to be established quickly for chemiosmosis (1)` },
      { q: 'Compare the ATP yield from aerobic and anaerobic respiration.', marks: 3, markScheme: `• Aerobic respiration produces approximately 30\u201332 ATP per glucose molecule (theoretical maximum of 38) (1)\n• Anaerobic respiration produces only 2 ATP per glucose (from glycolysis) (1)\n• Aerobic respiration is far more efficient because the Krebs cycle and oxidative phosphorylation generate most of the ATP, which requires oxygen (1)` },
      { q: 'Explain what is meant by the VO\u2082 max and why it is an indicator of fitness.', marks: 2, markScheme: `• VO\u2082 max is the maximum rate of oxygen consumption during intense exercise (1)\n• A higher VO\u2082 max indicates greater aerobic fitness / the body can deliver and use more oxygen for ATP production during exercise (1)` },
      { q: 'Describe how fast-twitch and slow-twitch muscle fibres differ in structure and function.', marks: 4, markScheme: `• Slow-twitch (Type I): contract slowly, are fatigue-resistant, and are suited to endurance activities (1)\n• They have many mitochondria, rich blood supply, and high myoglobin content for sustained aerobic respiration (1)\n• Fast-twitch (Type II): contract rapidly and powerfully but fatigue quickly (1)\n• They have fewer mitochondria but large glycogen stores and high anaerobic capacity for short bursts of intense activity (1)` },
      { q: 'Explain how negative feedback is involved in homeostasis.', marks: 3, markScheme: `• A receptor detects a change / deviation from the set point (1)\n• A control centre / coordinator processes the information and sends signals to effectors (1)\n• Effectors bring about a response that opposes / reverses the change, returning the variable to the set point (1)` },
      { q: 'Describe the role of insulin and glucagon in blood glucose regulation.', marks: 4, markScheme: `• When blood glucose rises (e.g. after a meal), beta cells of the pancreas secrete insulin (1)\n• Insulin stimulates cells to take up glucose and promotes glycogenesis (conversion of glucose to glycogen) in liver and muscle cells (1)\n• When blood glucose falls, alpha cells of the pancreas secrete glucagon (1)\n• Glucagon promotes glycogenolysis (breakdown of glycogen to glucose) and gluconeogenesis in the liver, raising blood glucose (1)` },
      { q: 'Explain why ATP is described as a universal energy currency.', marks: 3, markScheme: `• ATP is used by all living cells as an immediate source of energy (1)\n• It releases a small, manageable amount of energy when hydrolysed to ADP + Pi, suitable for individual reactions (1)\n• It can be rapidly regenerated from ADP and Pi, allowing continuous energy supply / it couples exergonic and endergonic reactions (1)` },
      { q: 'Describe the role of the respiratory substrate in determining the respiratory quotient (RQ).', marks: 3, markScheme: `• RQ = CO\u2082 produced / O\u2082 consumed (1)\n• Carbohydrates have an RQ of 1.0; fats have an RQ of approximately 0.7; proteins approximately 0.8 (1)\n• The RQ value indicates which substrate is being used predominantly for respiration (1)` },
      { q: 'Calculate the RQ if an organism produces 8 cm\u00b3 of CO\u2082 and consumes 10 cm\u00b3 of O\u2082.', marks: 2, markScheme: `• RQ = CO\u2082 produced / O\u2082 consumed = 8 / 10 (1)\n• RQ = 0.8 (suggesting protein or a mix of substrates is being respired) (1)` },
      { q: 'Explain the role of the sarcoplasmic reticulum in muscle contraction.', marks: 2, markScheme: `• The sarcoplasmic reticulum stores calcium ions at rest (1)\n• When stimulated by an action potential, it releases Ca\u00b2\u207a into the sarcoplasm, triggering the sliding filament mechanism (1)` },
      { q: 'Explain why training improves cardiovascular fitness.', marks: 4, markScheme: `• Regular exercise increases stroke volume by strengthening the cardiac muscle / cardiac hypertrophy (1)\n• Resting heart rate decreases because each beat pumps more blood (1)\n• The number of capillaries supplying muscles increases, improving oxygen delivery (1)\n• VO\u2082 max increases due to improved oxygen delivery and utilisation / more mitochondria in muscle cells (1)` },
      { q: 'Describe how a spirometer can be used to measure oxygen consumption and calculate the rate of respiration.', marks: 4, diagram: true, markScheme: `• The subject breathes in and out of a sealed chamber containing oxygen, connected to a recorder / data logger (1)\n• A CO\u2082 absorber (e.g. soda lime) removes exhaled CO\u2082 so only O\u2082 consumption is measured (1)\n• The volume of gas in the chamber decreases over time as oxygen is used up (1)\n• The rate of oxygen consumption is calculated from the gradient of the trace (volume decrease / time) (1)` },
      { q: 'Describe how lactate is removed from the body after exercise.', marks: 3, markScheme: `• Lactate is transported in the blood to the liver (1)\n• In the liver, lactate is converted back to pyruvate by lactate dehydrogenase (1)\n• Pyruvate can then be oxidised in aerobic respiration, or converted to glycogen for storage (Cori cycle) (1)` },
      { q: 'Explain why sustained vigorous exercise can cause muscle fatigue.', marks: 3, markScheme: `• During intense exercise, oxygen supply may be insufficient, leading to anaerobic respiration and lactate accumulation (1)\n• Lactate lowers pH in muscle cells, which inhibits enzyme activity and reduces the efficiency of muscle contraction (1)\n• Depletion of glycogen / creatine phosphate stores also reduces the ability to regenerate ATP rapidly (1)` },
      { q: 'Describe the role of the neuromuscular junction in stimulating muscle contraction.', marks: 4, markScheme: `• A nerve impulse / action potential arrives at the motor neurone terminal (1)\n• Calcium ions enter the terminal, causing synaptic vesicles to release acetylcholine (ACh) into the synaptic cleft (1)\n• ACh binds to receptors on the muscle fibre membrane (sarcolemma), depolarising it and generating an action potential (1)\n• The action potential spreads along the sarcolemma and into T-tubules, stimulating the sarcoplasmic reticulum to release Ca\u00b2\u207a (1)` },
      { q: 'Explain the significance of the inner mitochondrial membrane being folded into cristae.', marks: 2, markScheme: `• Cristae increase the surface area of the inner membrane (1)\n• This provides more space for electron transport chain complexes and ATP synthase, increasing the rate of oxidative phosphorylation / ATP production (1)` },
      { q: 'Explain why endurance athletes typically have a higher proportion of slow-twitch muscle fibres.', marks: 2, markScheme: `• Slow-twitch fibres are more resistant to fatigue and can sustain prolonged aerobic activity (1)\n• They have more mitochondria, myoglobin, and blood supply, enabling efficient aerobic ATP production for long-duration exercise (1)` },
      { q: 'Explain what happens to pyruvate when oxygen is present compared to when oxygen is absent.', marks: 3, markScheme: `• When oxygen is present: pyruvate enters the mitochondria and undergoes the link reaction to form acetyl CoA, which enters the Krebs cycle (1)\n• When oxygen is absent in animals: pyruvate is reduced to lactate in the cytoplasm (1)\n• When oxygen is absent in yeast: pyruvate is decarboxylated to ethanal then reduced to ethanol (1)` },
      { q: 'Explain how the structure of the alveoli is adapted for efficient gas exchange during exercise.', marks: 3, markScheme: `• Increased ventilation rate during exercise maintains a steep concentration gradient for O\u2082 and CO\u2082 across the alveolar walls (1)\n• The thin walls (one cell thick) and large surface area of alveoli allow rapid diffusion (1)\n• Increased cardiac output during exercise maintains blood flow past alveoli, ensuring continuous removal of O\u2082 and delivery of CO\u2082 (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── S8 */
  'S8': {
    name: 'Grey Matter',
    questions: [
      { q: 'State the function of the nervous system.', marks: 1, markScheme: `• To detect stimuli, coordinate responses, and enable communication between different parts of the body via electrical impulses (1)` },
      { q: 'Describe the structure of a motor neurone.', marks: 3, diagram: true, markScheme: `• Cell body with a nucleus, dendrites receiving impulses from other neurones, and a long axon transmitting impulses to effectors (1)\n• Axon is surrounded by a myelin sheath (Schwann cells) with gaps called nodes of Ranvier (1)\n• Axon terminals / synaptic knobs at the end of the axon release neurotransmitters (1)` },
      { q: 'Explain how a resting potential is maintained across a neurone membrane.', marks: 3, markScheme: `• The sodium-potassium pump actively transports 3 Na\u207a out and 2 K\u207a into the cell, using ATP (1)\n• K\u207a leak channels allow more K\u207a to diffuse out than Na\u207a diffuses in (1)\n• This creates a charge difference of approximately \u221270 mV across the membrane (inside negative relative to outside) (1)` },
      { q: 'Describe the events of an action potential.', marks: 5, markScheme: `• A stimulus causes sodium ion channels to open; Na\u207a rushes into the cell (depolarisation) (1)\n• The membrane potential rises from \u221270 mV towards +40 mV (1)\n• At the peak, sodium channels close and potassium channels open; K\u207a rushes out (repolarisation) (1)\n• Hyperpolarisation occurs as the membrane potential temporarily overshoots the resting potential (1)\n• The sodium-potassium pump restores the resting potential; there is a brief refractory period during which another action potential cannot be generated (1)` },
      { q: 'Explain the role of the myelin sheath in nerve impulse transmission.', marks: 3, markScheme: `• The myelin sheath is an insulating layer of fatty material that surrounds the axon (1)\n• Ions can only cross the membrane at the nodes of Ranvier (gaps in the myelin) (1)\n• The action potential jumps from node to node (saltatory conduction), which greatly increases the speed of transmission (1)` },
      { q: 'Explain what is meant by the all-or-nothing principle of action potentials.', marks: 2, markScheme: `• An action potential is only generated if the stimulus reaches the threshold level of depolarisation (1)\n• If the threshold is reached, the action potential is always the same size; a stronger stimulus does not produce a larger action potential (1)` },
      { q: 'Explain how a stronger stimulus is detected by the nervous system if action potentials are all-or-nothing.', marks: 2, markScheme: `• A stronger stimulus causes a higher frequency of action potentials / more action potentials per unit time (1)\n• A stronger stimulus may also recruit more neurones to fire simultaneously (1)` },
      { q: 'Describe the events at a cholinergic synapse.', marks: 5, markScheme: `• An action potential arrives at the presynaptic terminal and causes calcium ion channels to open (1)\n• Ca\u00b2\u207a influx causes synaptic vesicles to fuse with the presynaptic membrane, releasing acetylcholine (ACh) into the synaptic cleft by exocytosis (1)\n• ACh diffuses across the cleft and binds to specific receptors on the postsynaptic membrane (1)\n• This causes sodium ion channels to open, depolarising the postsynaptic membrane and potentially generating a new action potential (1)\n• ACh is rapidly broken down by acetylcholinesterase; choline is reabsorbed into the presynaptic neurone for recycling (1)` },
      { q: 'Explain the role of calcium ions in synaptic transmission.', marks: 2, markScheme: `• When an action potential reaches the presynaptic terminal, voltage-gated calcium channels open (1)\n• Ca\u00b2\u207a enters the terminal and triggers fusion of synaptic vesicles with the presynaptic membrane, causing neurotransmitter release (1)` },
      { q: 'Explain why synaptic transmission is unidirectional.', marks: 2, markScheme: `• Neurotransmitter vesicles are only present in the presynaptic terminal (1)\n• Receptors for the neurotransmitter are only on the postsynaptic membrane, so the signal can only travel in one direction (1)` },
      { q: 'Describe the structure of the human brain, including the cerebrum, cerebellum, and medulla oblongata.', marks: 4, markScheme: `• The cerebrum is the largest part of the brain, divided into two hemispheres; responsible for conscious thought, reasoning, memory, language, and voluntary movement (1)\n• The cerebral cortex is the outer layer of grey matter (cell bodies) with white matter (myelinated axons) beneath (1)\n• The cerebellum is at the back/base of the brain; it coordinates balance, posture, and fine motor movements (1)\n• The medulla oblongata is at the base of the brain connecting to the spinal cord; it controls involuntary functions such as heart rate, breathing rate, and blood pressure (1)` },
      { q: 'Describe the structure of the human eye and the role of the retina.', marks: 4, diagram: true, markScheme: `• The eye has a cornea (refracts light), iris (controls pupil size / amount of light entering), and lens (focuses light onto the retina) (1)\n• The retina is the light-sensitive layer at the back of the eye containing photoreceptor cells (1)\n• Rod cells are sensitive to dim light and provide black-and-white vision; cone cells detect colour and work in bright light (1)\n• Light stimulates photoreceptors to generate nerve impulses that are transmitted via the optic nerve to the brain (1)` },
      { q: 'Explain the difference between rod cells and cone cells.', marks: 4, markScheme: `• Rod cells are more sensitive to light / work in low light intensity; cone cells require brighter light (1)\n• Rods give black-and-white / monochrome vision; cones give colour vision (three types: red, green, blue) (1)\n• Many rods connect to a single bipolar neurone (convergence), increasing sensitivity but reducing acuity (1)\n• Each cone typically connects to its own bipolar neurone, giving high visual acuity but lower sensitivity (1)` },
      { q: 'Explain the role of rhodopsin in rod cells.', marks: 3, markScheme: `• Rhodopsin is a light-sensitive pigment in rod cells, composed of retinal and opsin (1)\n• When light hits rhodopsin, retinal changes shape (cis to trans), causing rhodopsin to break down / bleach (1)\n• This triggers a cascade of events that leads to a generator potential and ultimately a nerve impulse being sent to the brain (1)` },
      { q: 'Describe how the brain processes visual information from both eyes to produce depth perception.', marks: 2, markScheme: `• Each eye sees a slightly different image due to their different positions (binocular vision) (1)\n• The brain compares the two images in the visual cortex and uses the differences to judge distance / depth perception (1)` },
      { q: 'Explain the role of the hypothalamus in coordinating responses.', marks: 3, markScheme: `• The hypothalamus is the control centre for many homeostatic mechanisms (1)\n• It regulates body temperature by detecting blood temperature and coordinating vasodilation/vasoconstriction and sweating (1)\n• It also controls the pituitary gland, linking the nervous and endocrine systems / regulates water balance, hunger, and sleep (1)` },
      { q: 'Describe the concept of habituation as a type of learning.', marks: 3, markScheme: `• Habituation is a form of learning where an organism gradually stops responding to a repeated, harmless stimulus (1)\n• It occurs because fewer neurotransmitter vesicles are released at the synapse with repeated stimulation (1)\n• This is an adaptive behaviour that allows organisms to ignore insignificant stimuli and focus on important ones (1)` },
      { q: 'Explain how synaptic plasticity is involved in learning and memory.', marks: 3, markScheme: `• Repeated stimulation of a synapse can strengthen the connection between neurones (long-term potentiation / LTP) (1)\n• More neurotransmitter receptors may be produced on the postsynaptic membrane, or more neurotransmitter may be released (1)\n• New synaptic connections can form, creating neural pathways associated with memories (1)` },
      { q: 'Describe how drugs can affect synaptic transmission, using one example.', marks: 3, markScheme: `• Some drugs mimic neurotransmitters and bind to postsynaptic receptors, stimulating the postsynaptic neurone (agonists); e.g. nicotine mimics acetylcholine (1)\n• Some drugs block receptors, preventing the neurotransmitter from binding (antagonists); e.g. curare blocks ACh receptors (1)\n• Some drugs inhibit the breakdown or reuptake of neurotransmitters, prolonging their effect; e.g. SSRIs block serotonin reuptake (1)` },
      { q: 'Explain the neurological basis of Parkinson\u2019s disease.', marks: 3, markScheme: `• Parkinson\u2019s disease is caused by the death / degeneration of dopamine-producing neurones in the substantia nigra of the brain (1)\n• Reduced dopamine levels impair communication in the basal ganglia, which controls movement (1)\n• Symptoms include tremor, rigidity, slow movement (bradykinesia), and balance problems (1)` },
      { q: 'Describe how L-DOPA is used to treat Parkinson\u2019s disease and explain its limitations.', marks: 3, markScheme: `• L-DOPA is a precursor to dopamine that can cross the blood-brain barrier (dopamine itself cannot) (1)\n• In the brain, L-DOPA is converted to dopamine, partially restoring dopamine levels and reducing symptoms (1)\n• Limitations: effectiveness decreases over time, side effects include nausea and involuntary movements, and it does not stop the underlying neurodegeneration (1)` },
      { q: 'Describe the features of Alzheimer\u2019s disease.', marks: 3, markScheme: `• Alzheimer\u2019s is a neurodegenerative disease characterised by progressive memory loss, confusion, and cognitive decline (1)\n• Pathological features include amyloid plaques (extracellular deposits of beta-amyloid protein) between neurones (1)\n• Neurofibrillary tangles (twisted tau protein fibres) inside neurones, leading to neurone death and brain atrophy (1)` },
      { q: 'Explain how brain imaging techniques (e.g. MRI, fMRI, CT) are used in studying brain function.', marks: 4, markScheme: `• CT scans use X-rays to produce cross-sectional images of brain structure, useful for detecting tumours and bleeding (1)\n• MRI uses magnetic fields and radio waves to produce detailed structural images of the brain without radiation (1)\n• fMRI detects changes in blood flow / oxygenation to show which brain areas are active during specific tasks (1)\n• These techniques allow scientists to map brain function, diagnose disorders, and study the effects of damage or disease non-invasively (1)` },
      { q: 'Explain the concept of critical periods in brain development.', marks: 2, markScheme: `• Critical periods are specific time windows during development when the brain is particularly sensitive to certain stimuli / experiences (1)\n• If appropriate stimulation does not occur during the critical period (e.g. for language acquisition or vision), normal development may be permanently impaired (1)` },
      { q: 'Describe the role of the pupil reflex in protecting the eye.', marks: 3, markScheme: `• In bright light, the circular muscles of the iris contract and the radial muscles relax, constricting the pupil (1)\n• In dim light, the radial muscles contract and the circular muscles relax, dilating the pupil (1)\n• This is a reflex that protects the retina from damage by excessive light and maximises light entry in dim conditions (1)` },
      { q: 'Explain the difference between the central nervous system and the peripheral nervous system.', marks: 2, markScheme: `• The central nervous system (CNS) consists of the brain and spinal cord; it processes information and coordinates responses (1)\n• The peripheral nervous system (PNS) consists of sensory and motor neurones connecting the CNS to receptors and effectors throughout the body (1)` },
      { q: 'Explain the role of the refractory period in nerve impulse transmission.', marks: 2, markScheme: `• During the refractory period, sodium channels are inactivated and the membrane cannot be depolarised again immediately (1)\n• This ensures action potentials are discrete events, travel in one direction, and limits the maximum frequency of impulses (1)` },
      { q: 'Describe how sensory receptors convert a stimulus into a nerve impulse (transduction).', marks: 3, markScheme: `• A stimulus is detected by a receptor cell, causing ion channels to open or close (1)\n• This changes the permeability of the receptor cell membrane, producing a generator potential (1)\n• If the generator potential reaches the threshold, it triggers an action potential in the sensory neurone (1)` },
      { q: 'Explain the ethical issues surrounding the use of animals in brain research.', marks: 4, markScheme: `• Animal studies have provided valuable insights into brain function, drug development, and treatment of neurological diseases (1)\n• However, animals may experience pain, distress, and suffering during experiments (1)\n• There are questions about whether results from animal models can be reliably extrapolated to humans (1)\n• Ethical frameworks (e.g. the 3Rs: Replace, Reduce, Refine) aim to minimise animal use and suffering while still advancing scientific knowledge (1)` },
      { q: 'Describe how summation at a synapse can determine whether a postsynaptic action potential is generated.', marks: 3, markScheme: `• Temporal summation: multiple impulses from a single presynaptic neurone in quick succession build up neurotransmitter to reach the threshold (1)\n• Spatial summation: impulses from several presynaptic neurones converge on one postsynaptic neurone, combining their effects (1)\n• If the total depolarisation of the postsynaptic membrane reaches the threshold, an action potential is generated; if not, the signal is not transmitted (1)` },
      { q: 'Explain how drug tolerance develops with repeated use.', marks: 3, markScheme: `• With repeated exposure to a drug, the body may reduce the number of receptors (down-regulation) or produce less endogenous neurotransmitter (1)\n• The same dose of the drug produces a reduced effect over time (1)\n• The individual may need to increase the dose to achieve the same effect, which can lead to dependence and addiction (1)` },
      { q: 'Draw a labelled diagram of a synapse showing the key structures involved in transmission.', marks: 4, diagram: true, markScheme: `• Presynaptic terminal with synaptic vesicles containing neurotransmitter drawn and labelled (1)\n• Synaptic cleft between the two neurones shown (1)\n• Postsynaptic membrane with receptor proteins shown and labelled (1)\n• Mitochondria in the presynaptic terminal and calcium ion channels labelled (1)` },
      { q: 'Evaluate the use of drugs to treat depression by altering neurotransmitter levels.', marks: 4, markScheme: `• SSRIs block reuptake of serotonin, increasing its availability in the synaptic cleft and improving mood (1)\n• They are effective for many patients and have fewer side effects than older antidepressants (1)\n• However, they do not work for all patients, take weeks to show effects, and can have side effects such as nausea and anxiety (1)\n• The relationship between serotonin levels and depression is complex; drugs address symptoms but not underlying causes (1)` },
      { q: 'Explain why damage to specific areas of the brain can lead to loss of particular functions.', marks: 2, markScheme: `• Different brain regions are specialised for different functions (localisation of function) \u2014 e.g. Broca\u2019s area for speech production, visual cortex for vision (1)\n• Damage to a specific area disrupts the neural circuits responsible for that function, leading to specific deficits (e.g. damage to Broca\u2019s area causes speech difficulties) (1)` },
      { q: 'Describe how the fight-or-flight response is coordinated by the nervous and endocrine systems.', marks: 4, markScheme: `• A perceived threat activates the hypothalamus, which stimulates the sympathetic nervous system (1)\n• The adrenal medulla releases adrenaline into the bloodstream (1)\n• Adrenaline increases heart rate, breathing rate, and blood glucose levels, preparing the body for action (1)\n• Blood is diverted from the digestive system to skeletal muscles; pupils dilate to improve vision (1)` },
      { q: 'Explain how neuroplasticity allows the brain to recover from injury.', marks: 3, markScheme: `• Neuroplasticity is the brain\u2019s ability to form new neural connections and reorganise existing pathways (1)\n• After injury, undamaged areas of the brain may take over functions previously performed by the damaged area (1)\n• Rehabilitation exercises promote the formation of new synaptic connections, aiding functional recovery (1)` },
      { q: 'Describe the difference between sensory, relay and motor neurones.', marks: 3, markScheme: `• Sensory neurones carry impulses from receptors to the CNS; they have a long dendron and short axon (1)\n• Relay neurones (interneurones) are found within the CNS and connect sensory and motor neurones (1)\n• Motor neurones carry impulses from the CNS to effectors (muscles/glands); they have a long axon and short dendrites (1)` },
      { q: 'Explain how a reflex arc enables a rapid, involuntary response to a stimulus.', marks: 4, markScheme: `• A receptor detects a stimulus and generates a nerve impulse in a sensory neurone (1)\n• The impulse passes through a relay neurone in the spinal cord (1)\n• The relay neurone transmits the impulse to a motor neurone, which carries it to an effector (muscle/gland) (1)\n• The response is rapid and involuntary because it does not require processing by the brain / the pathway is short with few synapses (1)` },
      { q: 'Explain how the visual cortex processes information from the eyes to create an image.', marks: 3, markScheme: `• Nerve impulses from photoreceptors in the retina travel via the optic nerve to the visual cortex in the occipital lobe (1)\n• The visual cortex contains neurones that respond to specific features such as edges, shapes, colours, and movement (1)\n• Information from both eyes is integrated to form a complete visual image, including depth perception from binocular vision (1)` },
      { q: 'Describe the evidence that different parts of the cerebral cortex have different functions.', marks: 3, markScheme: `• Studies of patients with brain damage show that damage to specific areas causes specific functional loss (e.g. Broca\u2019s area damage impairs speech production) (1)\n• Electrical stimulation of different cortical areas during surgery produces specific responses (movement, sensations) (1)\n• Brain imaging (fMRI) shows that different regions are activated during different tasks (language, motor, visual) (1)` },
    ],
  },

};

